static uint32_t samp_asset_custom_low_preload_limit_compat(void) {
  return object_compat_env_u32(SAMP_OBJECT_COMPAT_CUSTOM_LOW_PRELOAD_ENV,
                               SAMP_OBJECT_COMPAT_CUSTOM_LOW_PRELOAD_DEFAULT, 0u,
                               SAMP_OBJECT_COMPAT_CUSTOM_LOW_PRELOAD_MAX);
}

static void samp_asset_request_custom_model_registration_compat(int32_t model, const char *source) {
  LONG count = 0;
  LONG i = 0;

  if (!object_compat_is_samp_custom_model(model) || object_compat_model_available(model)) {
    return;
  }
  if (samp_asset_registration_model_blocked_compat(model)) {
    return;
  }
  if (!samp_asset_custom_asset_register_enabled_compat()) {
    runtime_tracef("samp_asset_registration: request_skip model=%ld source=%s reason=disabled env=%s "
                   "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown", SAMP_OBJECT_COMPAT_CUSTOM_ASSET_REGISTER_ENV);
    return;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 0, 0) == 0) {
    samp_asset_index_build_compat();
  }
  if (samp_asset_model_lookup_compat(model) == NULL) {
    runtime_tracef("samp_asset_registration: request_skip model=%ld source=%s reason=missing_ide_entry "
                   "evidence=PROBE_TRACE,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown");
    return;
  }

  count = InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_count, 0, 0);
  if (count < 0) {
    InterlockedExchange(&g_runtime.samp_asset_register_pending_count, 0);
    count = 0;
  }
  if (count > (LONG)SAMP_ASSET_REGISTER_PENDING_MAX) {
    count = (LONG)SAMP_ASSET_REGISTER_PENDING_MAX;
  }

  for (i = 0; i < count; ++i) {
    if (InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_models[i], 0, 0) == model) {
      return;
    }
  }
  if (count >= (LONG)SAMP_ASSET_REGISTER_PENDING_MAX) {
    if (InterlockedCompareExchange(&g_runtime.samp_asset_register_overflow_logged, 1, 0) == 0) {
      runtime_tracef("samp_asset_registration: request_overflow model=%ld source=%s pending=%ld max=%lu "
                     "evidence=PROBE_TRACE,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", (long)count,
                     (unsigned long)SAMP_ASSET_REGISTER_PENDING_MAX);
    }
    return;
  }

  InterlockedExchange(&g_runtime.samp_asset_register_pending_models[count], model);
  InterlockedExchange(&g_runtime.samp_asset_register_pending_count, count + 1);
  runtime_tracef("samp_asset_registration: request model=%ld source=%s seq=%ld pending=%ld "
                 "evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                 (long)model, source != NULL ? source : "unknown",
                 (long)InterlockedIncrement(&g_runtime.samp_asset_register_request_seq), (long)(count + 1));
}

static int samp_asset_register_streaming_image_compat(const char *label, const char *path, LONG *image_id_slot) {
  gta_streaming_add_image_to_list_fn add_image =
      (gta_streaming_add_image_to_list_fn)(uintptr_t)SAMP_ADDR_STREAMING_ADD_IMAGE_TO_LIST;
  LONG encoded_image_id = 0;
  LONG image_id = 0;

  if (label == NULL || path == NULL || image_id_slot == NULL) {
    return 0;
  }
  encoded_image_id = InterlockedCompareExchange(image_id_slot, 0, 0);
  if (encoded_image_id > 0) {
    return 1;
  }
  if (encoded_image_id == -2) {
    return 0;
  }
  if (!gta_code_ptr_compat((uintptr_t)add_image)) {
    runtime_tracef("samp_asset_registration: archive_add_skip label=%s path='%s' reason=bad_add_image_fn "
                   "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   label, path);
    return 0;
  }

  /* OBSERVED_037 + PROBE_TRACE:
   * Original R5 assigns SAMP\CUSTOM.IMG image id 0 during early GTA image-list
   * setup. Store image_id + 1 locally so valid id 0 is distinguishable from the
   * "not attempted yet" state.
   */
  image_id = (LONG)add_image(path, 1);
  if (image_id < 0) {
    InterlockedExchange(image_id_slot, -2);
    runtime_tracef("samp_asset_registration: archive_add_fail label=%s path='%s' image_id=%ld "
                   "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   label, path, (long)image_id);
    return 0;
  }

  InterlockedExchange(image_id_slot, image_id + 1);
  runtime_tracef("samp_asset_registration: archive_add label=%s path='%s' image_id=%ld "
                 "encoded=%ld evidence=OBSERVED_037,GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                 label, path, (long)image_id, (long)(image_id + 1));
  return 1;
}

static void samp_asset_load_streaming_directory_compat(const char *label, const char *path, LONG image_id) {
  gta_streaming_load_cd_directory_fn load_cd_directory =
      (gta_streaming_load_cd_directory_fn)(uintptr_t)SAMP_ADDR_STREAMING_LOAD_CD_DIRECTORY;

  if (label == NULL || path == NULL || image_id < 0) {
    return;
  }
  if (!gta_code_ptr_compat((uintptr_t)load_cd_directory)) {
    runtime_tracef("samp_asset_registration: archive_dir_skip label=%s path='%s' image_id=%ld "
                   "reason=bad_load_cd_directory_fn evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   label, path, (long)image_id);
    return;
  }

  load_cd_directory(path, image_id);
  runtime_tracef("samp_asset_registration: archive_dir_loaded label=%s path='%s' image_id=%ld "
                 "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                 label, path, (long)image_id);
}

static int samp_asset_read_img_entry_data_compat(const char *label, const char *relative_path,
                                                 const samp_asset_img_entry_compat *entry, uint8_t **out_data,
                                                 DWORD *out_size) {
  HANDLE handle = INVALID_HANDLE_VALUE;
  uint64_t offset_bytes = 0u;
  uint64_t data_bytes = 0u;
  LONG offset_low = 0;
  LONG offset_high = 0;
  DWORD seek_low = 0u;
  uint8_t *buffer = NULL;

  if (out_data == NULL || out_size == NULL) {
    return 0;
  }
  *out_data = NULL;
  *out_size = 0u;
  if (label == NULL || relative_path == NULL || entry == NULL || entry->present == 0u ||
      g_runtime.bootstrap_shims.set_file_pointer == NULL) {
    return 0;
  }

  data_bytes = (uint64_t)entry->size_sectors * (uint64_t)SAMP_ASSET_IMG_SECTOR_BYTES;
  offset_bytes = (uint64_t)entry->offset_sectors * (uint64_t)SAMP_ASSET_IMG_SECTOR_BYTES;
  if (data_bytes == 0u || data_bytes > (uint64_t)SAMP_ASSET_COL_BUFFER_MAX || data_bytes > (uint64_t)0xFFFFFFFFu) {
    runtime_tracef("samp_asset_col: read_skip label=%s name='%s' reason=bad_size sectors=%lu bytes=%lu "
                   "max=%lu evidence=PROBE_TRACE,TODO_VERIFY",
                   label, entry->name, (unsigned long)entry->size_sectors, (unsigned long)data_bytes,
                   (unsigned long)SAMP_ASSET_COL_BUFFER_MAX);
    return 0;
  }

  if (!samp_asset_open_read_compat(label, relative_path, &handle, NULL, 0u)) {
    return 0;
  }
  offset_low = (LONG)(offset_bytes & 0xFFFFFFFFu);
  offset_high = (LONG)(offset_bytes >> 32u);
  SetLastError(NO_ERROR);
  seek_low = g_runtime.bootstrap_shims.set_file_pointer(handle, offset_low, &offset_high, FILE_BEGIN);
  if (seek_low == INVALID_SET_FILE_POINTER && GetLastError() != NO_ERROR) {
    runtime_tracef("samp_asset_col: seek_failed label=%s name='%s' offset=%lu:%lu err=%lu "
                   "evidence=PROBE_TRACE,TODO_VERIFY",
                   label, entry->name, (unsigned long)(offset_bytes >> 32u), (unsigned long)(offset_bytes & 0xFFFFFFFFu),
                   (unsigned long)GetLastError());
    g_runtime.bootstrap_shims.close_handle(handle);
    return 0;
  }

  buffer = (uint8_t *)HeapAlloc(GetProcessHeap(), 0u, (SIZE_T)data_bytes);
  if (buffer == NULL) {
    runtime_tracef("samp_asset_col: alloc_failed label=%s name='%s' bytes=%lu evidence=PROBE_TRACE,TODO_VERIFY",
                   label, entry->name, (unsigned long)data_bytes);
    g_runtime.bootstrap_shims.close_handle(handle);
    return 0;
  }
  if (!samp_asset_read_exact_compat(handle, buffer, (DWORD)data_bytes)) {
    runtime_tracef("samp_asset_col: read_failed label=%s name='%s' bytes=%lu err=%lu "
                   "evidence=PROBE_TRACE,TODO_VERIFY",
                   label, entry->name, (unsigned long)data_bytes, (unsigned long)GetLastError());
    HeapFree(GetProcessHeap(), 0u, buffer);
    g_runtime.bootstrap_shims.close_handle(handle);
    return 0;
  }

  g_runtime.bootstrap_shims.close_handle(handle);
  *out_data = buffer;
  *out_size = (DWORD)data_bytes;
  return 1;
}

static int samp_asset_load_sampcol_collision_compat(const char *source) {
  static LONG in_progress = 0;
  static LONG loaded_once = 0;
  static LONG col_slot_plus_one = 0;
  static LONG load_attempts = 0;
  static LONG last_bound_count = 0;
  gta_colstore_add_col_slot_fn add_col_slot = (gta_colstore_add_col_slot_fn)(uintptr_t)SAMP_ADDR_COLSTORE_ADD_COL_SLOT;
  gta_colstore_load_col_buffer_fn load_col_buffer =
      (gta_colstore_load_col_buffer_fn)(uintptr_t)SAMP_ADDR_COLSTORE_LOAD_COL_BUFFER;
  gta_fileloader_load_collision_first_time_fn load_col_first_time =
      (gta_fileloader_load_collision_first_time_fn)(uintptr_t)SAMP_ADDR_FILELOADER_LOAD_COLLISION_FIRST_TIME;
  const samp_asset_img_entry_compat *entry = NULL;
  uint8_t *data = NULL;
  DWORD data_size = 0u;
  int32_t col_slot = -1;
  int ok = 0;
  LONG registered_before = 0;
  LONG registered_after = 0;
  LONG bound_before = 0;
  LONG bound_after = 0;
  LONG attempt = 0;
  LONG current_slot_plus_one = 0;

  if (InterlockedCompareExchange(&in_progress, 1, 0) != 0) {
    return 0;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 0, 0) == 0) {
    samp_asset_index_build_compat();
  }
  if (!gta_code_ptr_compat((uintptr_t)add_col_slot) || !gta_code_ptr_compat((uintptr_t)load_col_buffer) ||
      !gta_code_ptr_compat((uintptr_t)load_col_first_time)) {
    runtime_tracef("samp_asset_col: load_skip source=%s reason=bad_col_fns add_slot=0x%08lx load_buffer=0x%08lx "
                   "load_first_time=0x%08lx "
                   "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   source != NULL ? source : "unknown", (unsigned long)SAMP_ADDR_COLSTORE_ADD_COL_SLOT,
                   (unsigned long)SAMP_ADDR_COLSTORE_LOAD_COL_BUFFER,
                   (unsigned long)SAMP_ADDR_FILELOADER_LOAD_COLLISION_FIRST_TIME);
    InterlockedExchange(&in_progress, 0);
    return 0;
  }

  entry = samp_asset_find_img_entry_compat(SAMP_ASSET_ALL_SAMPCOLS_NAME);
  if (entry == NULL || entry->archive != SAMP_ASSET_ARCHIVE_SAMPCOL_IMG) {
    runtime_tracef("samp_asset_col: load_skip source=%s reason=missing_allsampcols col_entries=%ld "
                   "evidence=OBSERVED_037,PROBE_TRACE,TODO_VERIFY",
                   source != NULL ? source : "unknown", (long)g_runtime.samp_asset_col_entry_count);
    InterlockedExchange(&in_progress, 0);
    return 0;
  }
  if (!samp_asset_read_img_entry_data_compat("sampcol_img_data", "SAMP\\SAMPCOL.IMG", entry, &data, &data_size)) {
    InterlockedExchange(&in_progress, 0);
    return 0;
  }

  current_slot_plus_one = InterlockedCompareExchange(&col_slot_plus_one, 0, 0);
  if (current_slot_plus_one > 0) {
    col_slot = (int32_t)(current_slot_plus_one - 1);
  } else {
    col_slot = add_col_slot("AllSAMPCOLs");
    if (col_slot >= 0 && col_slot <= 255 &&
        InterlockedCompareExchange(&col_slot_plus_one, (LONG)col_slot + 1, 0) != 0) {
      current_slot_plus_one = InterlockedCompareExchange(&col_slot_plus_one, 0, 0);
      if (current_slot_plus_one > 0) {
        col_slot = (int32_t)(current_slot_plus_one - 1);
      }
    }
  }
  if (col_slot < 0 || col_slot > 255) {
    runtime_tracef("samp_asset_col: load_skip source=%s reason=bad_col_slot slot=%ld name='%s' bytes=%lu "
                   "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                   source != NULL ? source : "unknown", (long)col_slot, entry->name, (unsigned long)data_size);
    HeapFree(GetProcessHeap(), 0u, data);
    InterlockedExchange(&in_progress, 0);
    return 0;
  }

  bound_before = samp_asset_count_bound_custom_col_models_compat(&registered_before);
  attempt = InterlockedIncrement(&load_attempts);
  if (InterlockedCompareExchange(&loaded_once, 0, 0) == 0) {
    ok = load_col_buffer(col_slot, data, (int32_t)data_size);
  } else {
    /*
     * GTA_REVERSED_REF + PROBE_TRACE + TODO_VERIFY:
     * CColStore::LoadCol switches to CFileLoader::LoadCollisionFile after a slot is
     * marked loaded. That path searches only inside the slot's recorded model range,
     * so newly registered SA-MP ModelInfos can remain unbound. The first-time loader
     * performs the global name/key lookup and IncludeModelIndex step that late
     * targeted registration needs.
     */
    ok = load_col_first_time(data, data_size, (uint8_t)col_slot);
  }
  bound_after = samp_asset_count_bound_custom_col_models_compat(&registered_after);
  runtime_tracef("samp_asset_col: load source=%s ok=%d attempt=%ld slot=%ld loaded_once=%ld name='%s' "
                 "offset_sectors=%lu size_sectors=%lu bytes=%lu registered=%ld->%ld col_bound=%ld->%ld "
                 "last_bound=%ld loader=%s add_slot=0x%08lx load_buffer=0x%08lx load_first_time=0x%08lx "
                 "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                 source != NULL ? source : "unknown", ok, (long)attempt, (long)col_slot,
                 (long)InterlockedCompareExchange(&loaded_once, 0, 0), entry->name,
                 (unsigned long)entry->offset_sectors, (unsigned long)entry->size_sectors, (unsigned long)data_size,
                 (long)registered_before, (long)registered_after, (long)bound_before, (long)bound_after,
                 (long)InterlockedCompareExchange(&last_bound_count, 0, 0),
                 InterlockedCompareExchange(&loaded_once, 0, 0) == 0 ? "colstore" : "first_time",
                 (unsigned long)SAMP_ADDR_COLSTORE_ADD_COL_SLOT, (unsigned long)SAMP_ADDR_COLSTORE_LOAD_COL_BUFFER,
                 (unsigned long)SAMP_ADDR_FILELOADER_LOAD_COLLISION_FIRST_TIME);
  HeapFree(GetProcessHeap(), 0u, data);
  if (ok) {
    InterlockedExchange(&loaded_once, 1);
    if (bound_after > bound_before || bound_after > InterlockedCompareExchange(&last_bound_count, 0, 0)) {
      InterlockedExchange(&last_bound_count, bound_after);
    }
  }
  InterlockedExchange(&in_progress, 0);
  return ok != 0;
}

static int samp_asset_register_streaming_archives_compat(const char *source, int force_directory_reload) {
  static LONG samp_img_id = -1;
  static LONG custom_img_id = -1;
  static LONG sampcol_img_id = -1;
  static LONG directories_loaded = 0;
  static LONG directory_reload_count = 0;
  static LONG directory_reload_limit_logged = 0;
  LONG current_samp_img_id = 0;
  LONG current_custom_img_id = 0;
  LONG current_sampcol_img_id = 0;
  int load_directories = 0;
  const char *load_reason = "none";
  uint32_t reload_limit = 0u;

  (void)samp_asset_register_streaming_image_compat("custom_img", "SAMP\\CUSTOM.IMG", &custom_img_id);
  (void)samp_asset_register_streaming_image_compat("samp_img", "SAMP\\SAMP.IMG", &samp_img_id);
  (void)samp_asset_register_streaming_image_compat("sampcol_img", "SAMP\\SAMPCOL.IMG", &sampcol_img_id);

  current_samp_img_id = InterlockedCompareExchange(&samp_img_id, 0, 0) - 1;
  current_custom_img_id = InterlockedCompareExchange(&custom_img_id, 0, 0) - 1;
  current_sampcol_img_id = InterlockedCompareExchange(&sampcol_img_id, 0, 0) - 1;

  if (current_custom_img_id >= 0 || current_samp_img_id >= 0 || current_sampcol_img_id >= 0) {
    if (InterlockedCompareExchange(&directories_loaded, 1, 0) == 0) {
      load_directories = 1;
      load_reason = "initial";
    } else if (force_directory_reload) {
      LONG reload_before = InterlockedCompareExchange(&directory_reload_count, 0, 0);
      reload_limit = samp_asset_custom_asset_dir_reload_limit_compat();
      if (reload_before < (LONG)reload_limit) {
        LONG reload_after = InterlockedIncrement(&directory_reload_count);
        if (reload_after <= (LONG)reload_limit) {
          load_directories = 1;
          load_reason = "targeted_reload";
        }
      } else if (reload_limit != 0u && InterlockedCompareExchange(&directory_reload_limit_logged, 1, 0) == 0) {
        runtime_tracef("samp_asset_registration: archive_dir_reload_skip source=%s reason=limit reloads=%ld max=%lu "
                       "env=%s evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                       source != NULL ? source : "unknown", (long)reload_before, (unsigned long)reload_limit,
                       SAMP_OBJECT_COMPAT_CUSTOM_ASSET_DIR_RELOAD_ENV);
      }
    }
  }

  if (load_directories) {
    runtime_tracef("samp_asset_registration: archive_dir_batch source=%s reason=%s reloads=%ld max=%lu "
                   "ids=(custom:%ld,samp:%ld,sampcol:%ld) evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                   source != NULL ? source : "unknown", load_reason,
                   (long)InterlockedCompareExchange(&directory_reload_count, 0, 0),
                   (unsigned long)samp_asset_custom_asset_dir_reload_limit_compat(), (long)current_custom_img_id,
                   (long)current_samp_img_id, (long)current_sampcol_img_id);
    samp_asset_load_streaming_directory_compat("custom_img", "SAMP\\CUSTOM.IMG", current_custom_img_id);
    samp_asset_load_streaming_directory_compat("samp_img", "SAMP\\SAMP.IMG", current_samp_img_id);
    samp_asset_load_streaming_directory_compat("sampcol_img", "SAMP\\SAMPCOL.IMG", current_sampcol_img_id);
  }

  (void)samp_asset_load_sampcol_collision_compat(source);
  return current_custom_img_id >= 0 || current_samp_img_id >= 0 || current_sampcol_img_id >= 0;
}

static int samp_asset_write_model_info_metadata_compat(uintptr_t model_info, uint32_t key, int32_t txd_slot,
                                                       float ide_draw_distance) {
  float draw_distance = ide_draw_distance;
  int16_t txd_index = (int16_t)txd_slot;

  if (model_info < 0x10000u || !memory_is_writable_compat((void *)model_info, 0x20u)) {
    return 0;
  }
  if (!isfinite(draw_distance) || draw_distance <= 0.0f) {
    draw_distance = 2000.0f;
  } else if (draw_distance > 2000.0f) {
    draw_distance = 2000.0f;
  }
  memcpy((void *)(model_info + SAMP_MODEL_INFO_OFFSET_KEY), &key, sizeof(key));
  memcpy((void *)(model_info + SAMP_MODEL_INFO_OFFSET_TXD_INDEX), &txd_index, sizeof(txd_index));
  memcpy((void *)(model_info + SAMP_MODEL_INFO_OFFSET_DRAW_DISTANCE), &draw_distance, sizeof(draw_distance));
  return 1;
}

static int samp_asset_atomic_model_store_expanded_compat(void);
static uintptr_t samp_asset_atomic_model_store_count_addr_compat(void);
static unsigned long samp_asset_atomic_model_store_capacity_compat(void);

static int samp_asset_read_model_info_store_count_compat(uintptr_t add_model_addr, LONG *count_out) {
  uintptr_t count_addr = 0u;
  LONG count = -1;

  if (count_out != NULL) {
    *count_out = count;
  }

  switch (add_model_addr) {
  case SAMP_ADDR_MODEL_INFO_ADD_ATOMIC:
    count_addr = samp_asset_atomic_model_store_count_addr_compat();
    break;
  case SAMP_ADDR_MODEL_INFO_ADD_TIME:
    count_addr = SAMP_ADDR_MODEL_INFO_TIME_STORE_COUNT;
    break;
  case SAMP_ADDR_MODEL_INFO_ADD_CLUMP:
    count_addr = SAMP_ADDR_MODEL_INFO_CLUMP_STORE_COUNT;
    break;
  default:
    return 0;
  }

  if (!memory_is_readable_compat((const void *)count_addr, sizeof(count))) {
    return 0;
  }
  memcpy(&count, (const void *)count_addr, sizeof(count));
  if (count_out != NULL) {
    *count_out = count;
  }
  return 1;
}

static uintptr_t samp_asset_find_atomic_model_info_template_compat(int32_t *out_model) {
  static const int32_t candidates[] = {1337, 1225, 1231, 1278, 1290, 1294, 1297, 1300, 1315, 1339, 1362, 1437, 3095};
  size_t i = 0u;

  if (out_model != NULL) {
    *out_model = -1;
  }

  for (i = 0u; i < sizeof(candidates) / sizeof(candidates[0]); ++i) {
    int32_t model = candidates[i];
    uintptr_t model_info = object_compat_model_info_ptr(model);
    uintptr_t vtable = 0u;
    uintptr_t first_virtual = 0u;

    if (model_info < 0x10000u ||
        !memory_is_readable_compat((const void *)model_info, SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES)) {
      continue;
    }
    memcpy(&vtable, (const void *)model_info, sizeof(vtable));
    if (vtable < 0x10000u || !memory_is_readable_compat((const void *)vtable, sizeof(first_virtual))) {
      continue;
    }
    memcpy(&first_virtual, (const void *)vtable, sizeof(first_virtual));
    if (!gta_code_ptr_compat(first_virtual)) {
      continue;
    }
    if (out_model != NULL) {
      *out_model = model;
    }
    return model_info;
  }

  return 0u;
}

static int samp_asset_write_model_info_slot_compat(int32_t model, uintptr_t model_info) {
  uintptr_t slot_addr = 0u;

  if (!object_compat_model_plausible(model) || model_info < 0x10000u) {
    return 0;
  }
  slot_addr = (uintptr_t)SAMP_ADDR_MODEL_INFO_PTRS + ((uintptr_t)model * sizeof(uintptr_t));
  if (!memory_is_writable_compat((void *)slot_addr, sizeof(model_info))) {
    return 0;
  }
  memcpy((void *)slot_addr, &model_info, sizeof(model_info));
  return object_compat_model_info_ptr(model) == model_info;
}

static void samp_asset_clear_model_info_col_compat(uintptr_t model_info) {
  uintptr_t zero = 0u;

  if (model_info >= 0x10000u &&
      memory_is_writable_compat((void *)(model_info + SAMP_MODEL_INFO_OFFSET_COL_MODEL), sizeof(zero))) {
    memcpy((void *)(model_info + SAMP_MODEL_INFO_OFFSET_COL_MODEL), &zero, sizeof(zero));
  }
}

static int samp_asset_atomic_model_store_expanded_compat(void) {
  return InterlockedCompareExchange(&g_runtime.samp_asset_atomic_store_expanded, 0, 0) != 0 &&
         g_runtime.samp_asset_atomic_store_dynamic >= 0x10000u;
}

static uintptr_t samp_asset_atomic_model_store_count_addr_compat(void) {
  if (samp_asset_atomic_model_store_expanded_compat()) {
    return g_runtime.samp_asset_atomic_store_dynamic;
  }
  return SAMP_ADDR_MODEL_INFO_ATOMIC_STORE_COUNT;
}

static unsigned long samp_asset_atomic_model_store_capacity_compat(void) {
  if (samp_asset_atomic_model_store_expanded_compat() &&
      g_runtime.samp_asset_atomic_store_capacity >= SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT) {
    return g_runtime.samp_asset_atomic_store_capacity;
  }
  return SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT;
}

static int samp_asset_register_synthetic_atomic_model_info_compat(const samp_asset_model_entry_compat *model_entry,
                                                                  gta_keygen_get_uppercase_key_fn get_key,
                                                                  int32_t txd_slot, LONG store_count,
                                                                  unsigned long store_capacity, const char *source,
                                                                  int log_detail) {
  int32_t model = 0;
  int32_t template_model = -1;
  uintptr_t template_info = 0u;
  uintptr_t model_info = 0u;
  uintptr_t slot_before = 0u;
  uintptr_t slot_after = 0u;
  uint32_t key = 0u;
  int metadata_written = 0;
  int slot_written = 0;

  if (model_entry == NULL || model_entry->present == 0u) {
    return 0;
  }
  model = model_entry->model_id;
  if (!object_compat_is_samp_custom_model(model)) {
    return 0;
  }
  if (object_compat_model_available(model)) {
    return 1;
  }
  if (!gta_code_ptr_compat((uintptr_t)get_key)) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: synthetic_atomic_skip model=%ld source=%s reason=bad_key_fn "
                     "key=0x%08lx evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown",
                     (unsigned long)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY);
    }
    return 0;
  }

  slot_before = object_compat_model_info_ptr(model);
  if (slot_before != 0u && g_runtime.samp_asset_synthetic_atomic_model_infos[model] == 0u) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: synthetic_atomic_skip model=%ld source=%s reason=slot_occupied "
                     "slot=0x%08lx evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", (unsigned long)slot_before);
    }
    return object_compat_model_available(model);
  }

  model_info = g_runtime.samp_asset_synthetic_atomic_model_infos[model];
  if (model_info == 0u) {
    template_info = samp_asset_find_atomic_model_info_template_compat(&template_model);
    if (template_info == 0u) {
      if (log_detail) {
        runtime_tracef("samp_asset_registration: synthetic_atomic_skip model=%ld source=%s reason=no_template "
                       "store_count=%ld evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                       (long)model, source != NULL ? source : "unknown", (long)store_count);
      }
      return 0;
    }

    model_info = (uintptr_t)HeapAlloc(GetProcessHeap(), HEAP_ZERO_MEMORY, SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);
    if (model_info == 0u) {
      if (log_detail) {
        runtime_tracef("samp_asset_registration: synthetic_atomic_skip model=%ld source=%s reason=alloc_failed "
                       "bytes=%lu evidence=PROBE_TRACE,TODO_VERIFY",
                       (long)model, source != NULL ? source : "unknown",
                       (unsigned long)SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);
      }
      return 0;
    }
    memcpy((void *)model_info, (const void *)template_info, SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);
    samp_asset_clear_model_info_col_compat(model_info);
    g_runtime.samp_asset_synthetic_atomic_model_infos[model] = model_info;
    InterlockedIncrement(&g_runtime.samp_asset_synthetic_atomic_model_count);
  }

  key = get_key(model_entry->model_name);
  metadata_written = samp_asset_write_model_info_metadata_compat(model_info, key, txd_slot, model_entry->draw_distance);
  slot_written = samp_asset_write_model_info_slot_compat(model, model_info);
  slot_after = object_compat_model_info_ptr(model);
  if (!slot_written || !object_compat_model_available(model)) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: synthetic_atomic_failed model=%ld source=%s model_info=0x%08lx "
                     "slot_before=0x%08lx slot_after=0x%08lx slot_written=%d metadata_written=%d key=0x%08lx "
                     "txd_slot=%ld evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", (unsigned long)model_info,
                     (unsigned long)slot_before, (unsigned long)slot_after, slot_written, metadata_written,
                     (unsigned long)key, (long)txd_slot);
    }
    return 0;
  }

  if (log_detail) {
    runtime_tracef("samp_asset_registration: synthetic_atomic model=%ld source=%s model_info=0x%08lx "
                   "slot_before=0x%08lx slot_after=0x%08lx template_model=%ld store_count=%ld "
                   "store_capacity=%lu key=0x%08lx txd_slot=%ld draw=%.3f total=%ld "
                   "evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown", (unsigned long)model_info,
                   (unsigned long)slot_before, (unsigned long)slot_after, (long)template_model, (long)store_count,
                   store_capacity, (unsigned long)key, (long)txd_slot, (double)model_entry->draw_distance,
                   (long)InterlockedCompareExchange(&g_runtime.samp_asset_synthetic_atomic_model_count, 0, 0));
  }
  return 1;
}

static int samp_asset_model_info_store_has_capacity_compat(uintptr_t add_model_addr, LONG *count_out,
                                                           unsigned long *capacity_out) {
  static LONG logged_atomic_over_vanilla = 0;
  static LONG logged_atomic_over_vanilla_blocked = 0;
  unsigned long capacity = 0ul;
  LONG count = -1;

  if (count_out != NULL) {
    *count_out = count;
  }
  if (capacity_out != NULL) {
    *capacity_out = capacity;
  }

  switch (add_model_addr) {
  case SAMP_ADDR_MODEL_INFO_ADD_ATOMIC:
    capacity = samp_asset_atomic_model_store_capacity_compat();
    break;
  case SAMP_ADDR_MODEL_INFO_ADD_TIME:
    capacity = SAMP_GTA_TIME_MODEL_INFO_COUNT;
    break;
  case SAMP_ADDR_MODEL_INFO_ADD_CLUMP:
    capacity = SAMP_GTA_CLUMP_MODEL_INFO_COUNT;
    break;
  default:
    return 1;
  }

  if (capacity_out != NULL) {
    *capacity_out = capacity;
  }
  if (!samp_asset_read_model_info_store_count_compat(add_model_addr, &count)) {
    return 0;
  }
  if (count_out != NULL) {
    *count_out = count;
  }
  if (add_model_addr == SAMP_ADDR_MODEL_INFO_ADD_ATOMIC && count >= (LONG)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT) {
    if (!samp_asset_atomic_model_store_expanded_compat()) {
      int over_vanilla_requested = samp_asset_custom_asset_over_vanilla_enabled_compat();
      capacity = SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT;
      if (capacity_out != NULL) {
        *capacity_out = capacity;
      }
      if (count < (LONG)SAMP_GTA_ATOMIC_MODEL_INFO_COUNT &&
          InterlockedCompareExchange(&logged_atomic_over_vanilla_blocked, 1, 0) == 0) {
        runtime_tracef("samp_asset_registration: atomic_store_over_vanilla_blocked count=%ld vanilla=%u "
                       "observed_max=%u expand_env=%s over_env=%s over_requested=%d "
                       "evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                       (long)count, (unsigned)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT,
                       (unsigned)SAMP_GTA_ATOMIC_MODEL_INFO_COUNT, SAMP_OBJECT_COMPAT_ATOMIC_STORE_EXPAND_ENV,
                       SAMP_OBJECT_COMPAT_CUSTOM_ASSET_OVER_VANILLA_ENV, over_vanilla_requested);
      }
    } else if (count < (LONG)capacity &&
               InterlockedCompareExchange(&logged_atomic_over_vanilla, 1, 0) == 0) {
      runtime_tracef("samp_asset_registration: atomic_store_over_vanilla count=%ld vanilla=%u capacity=%lu "
                     "expand=1 evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                     (long)count, (unsigned)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT,
                     capacity);
    }
  }
  return count >= 0 && count < (LONG)capacity;
}

static uintptr_t samp_asset_model_info_add_addr_for_entry_compat(const samp_asset_model_entry_compat *model_entry) {
  if (model_entry != NULL && model_entry->section == SAMP_ASSET_IDE_SECTION_TOBJ) {
    return SAMP_ADDR_MODEL_INFO_ADD_TIME;
  }
  return SAMP_ADDR_MODEL_INFO_ADD_ATOMIC;
}

static const char *samp_asset_model_info_kind_for_addr_compat(uintptr_t add_model_addr) {
  switch (add_model_addr) {
  case SAMP_ADDR_MODEL_INFO_ADD_ATOMIC:
    return "atomic";
  case SAMP_ADDR_MODEL_INFO_ADD_TIME:
    return "time";
  case SAMP_ADDR_MODEL_INFO_ADD_CLUMP:
    return "clump";
  default:
    return "unknown";
  }
}

static gta_model_info_add_atomic_fn
samp_asset_model_info_add_fn_for_entry_compat(const samp_asset_model_entry_compat *model_entry) {
  return (gta_model_info_add_atomic_fn)samp_asset_model_info_add_addr_for_entry_compat(model_entry);
}

static int samp_asset_register_model_info_entry_compat(const samp_asset_model_entry_compat *model_entry,
                                                       gta_model_info_add_atomic_fn add_model_info,
                                                       gta_keygen_get_uppercase_key_fn get_key,
                                                       gta_txd_find_slot_fn find_slot,
                                                       gta_txd_add_slot_fn add_slot,
                                                       const char *source, int log_detail) {
  char dff_name[SAMP_ASSET_NAME_BYTES + 8u];
  char txd_name[SAMP_ASSET_NAME_BYTES + 8u];
  const char *txd_base = NULL;
  const samp_asset_img_entry_compat *dff_entry = NULL;
  const samp_asset_img_entry_compat *txd_entry = NULL;
  uintptr_t model_info = 0u;
  uintptr_t returned_model_info = 0u;
  uintptr_t slot_model_info = 0u;
  uintptr_t add_model_addr = (uintptr_t)add_model_info;
  const char *model_info_kind = samp_asset_model_info_kind_for_addr_compat(add_model_addr);
  uint32_t key = 0u;
  int32_t txd_slot = -1;
  int32_t model = 0;
  LONG model_info_store_count = -1;
  unsigned long model_info_store_capacity = 0ul;
  int metadata_enabled = 0;
  int metadata_written = 0;

  if (model_entry == NULL || model_entry->present == 0u) {
    return 0;
  }
  model = model_entry->model_id;
  if (!object_compat_is_samp_custom_model(model)) {
    return 0;
  }
  if (object_compat_model_available(model)) {
    return 1;
  }

  samp_asset_make_ext_name_compat(dff_name, sizeof(dff_name), model_entry->model_name, "dff");
  samp_asset_make_ext_name_compat(txd_name, sizeof(txd_name),
                                  model_entry->txd_name[0] != '\0' ? model_entry->txd_name : model_entry->model_name,
                                  "txd");
  dff_entry = samp_asset_find_img_entry_compat(dff_name);
  txd_entry = samp_asset_find_img_entry_compat(txd_name);
  if (dff_entry == NULL) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: proceed model=%ld source=%s note=missing_dff_index dff='%s' "
                     "evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", dff_name);
    }
  }

  txd_base = model_entry->txd_name[0] != '\0' ? model_entry->txd_name : model_entry->model_name;
  if (txd_base != NULL && txd_base[0] != '\0' && gta_code_ptr_compat((uintptr_t)find_slot)) {
    txd_slot = find_slot(txd_base);
  }
  if (txd_slot < 0 && txd_entry != NULL && gta_code_ptr_compat((uintptr_t)add_slot)) {
    txd_slot = add_slot(txd_base);
  }

  metadata_enabled = samp_asset_custom_asset_metadata_enabled_compat();
  if (!gta_code_ptr_compat((uintptr_t)add_model_info) ||
      (metadata_enabled && !gta_code_ptr_compat((uintptr_t)get_key))) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: skip model=%ld source=%s reason=bad_model_info_fns "
                     "class=%s add_model=0x%08lx key=0x%08lx metadata_enabled=%d "
                     "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown",
                     model_info_kind, (unsigned long)add_model_addr,
                     (unsigned long)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY, metadata_enabled);
    }
    return 0;
  }

  if (add_model_addr == SAMP_ADDR_MODEL_INFO_ADD_ATOMIC &&
      !samp_asset_atomic_model_store_expanded_compat() &&
      samp_asset_read_model_info_store_count_compat(add_model_addr, &model_info_store_count) &&
      model_info_store_count >= (LONG)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT) {
    /* OBSERVED_037 + PROBE_TRACE:
     * Original 0.3.7-R5 reaches AtomicModelInfo count 15417 and exposes valid
     * ms_modelInfoPtrs slots for low SAMP models such as 11682..11687. The
     * replacement still cannot call native AddAtomicModel once the vanilla
     * backing store is at its 14000-entry ceiling, so the synthetic 0x20 entry
     * remains limited to that over-vanilla fallback.
     */
    model_info_store_capacity = SAMP_GTA_ATOMIC_MODEL_INFO_COUNT;
    return samp_asset_register_synthetic_atomic_model_info_compat(
        model_entry, get_key, txd_slot, model_info_store_count, model_info_store_capacity, source, log_detail);
  }

  if (!samp_asset_model_info_store_has_capacity_compat(add_model_addr, &model_info_store_count,
                                                       &model_info_store_capacity)) {
    samp_asset_registration_block_model_compat(model, source, "model_info_store_full", model_info_kind,
                                               model_info_store_count, model_info_store_capacity, add_model_addr);
    if (log_detail) {
      runtime_tracef("samp_asset_registration: skip model=%ld source=%s reason=model_info_store_full "
                     "class=%s count=%ld max=%lu add_model=0x%08lx "
                     "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", model_info_kind,
                     (long)model_info_store_count, model_info_store_capacity, (unsigned long)add_model_addr);
    }
    return 0;
  }

  returned_model_info = add_model_info(model);
  slot_model_info = object_compat_model_info_ptr(model);
  model_info = slot_model_info != 0u ? slot_model_info : returned_model_info;
  if (model_info == 0u || !memory_is_readable_compat((const void *)model_info, 0x20u)) {
    if (log_detail) {
      runtime_tracef("samp_asset_registration: add_model_failed model=%ld source=%s model_info=0x%08lx "
                     "returned=0x%08lx slot=0x%08lx "
                     "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown", (unsigned long)model_info,
                     (unsigned long)returned_model_info, (unsigned long)slot_model_info);
    }
    return 0;
  }

  if (metadata_enabled && gta_code_ptr_compat((uintptr_t)get_key)) {
    key = get_key(model_entry->model_name);
    metadata_written = samp_asset_write_model_info_metadata_compat(model_info, key, txd_slot,
                                                                   model_entry->draw_distance);
  }

  if (log_detail) {
    runtime_tracef("samp_asset_registration: model=%ld source=%s model_info=0x%08lx returned=0x%08lx "
                   "slot=0x%08lx class=%s add_model=0x%08lx key=0x%08lx metadata_enabled=%d metadata_written=%d "
                   "store_count_before=%ld store_capacity=%lu name='%s' txd='%s' txd_slot=%ld "
                   "draw=%.3f flags=0x%08lx dff='%s' dff_archive=%s txd_file=%d "
                   "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown", (unsigned long)model_info,
                   (unsigned long)returned_model_info, (unsigned long)slot_model_info,
                   model_info_kind, (unsigned long)add_model_addr, (unsigned long)key, metadata_enabled,
                   metadata_written, (long)model_info_store_count, model_info_store_capacity,
                   model_entry->model_name, txd_base != NULL ? txd_base : "", (long)txd_slot,
                   (double)model_entry->draw_distance, (unsigned long)model_entry->flags, dff_name,
                   dff_entry != NULL ? samp_asset_archive_label_compat(dff_entry->archive) : "missing",
                   txd_entry != NULL ? 1 : 0);
  }
  return object_compat_model_available(model);
}

static int samp_asset_low_preload_source_enabled_compat(const char *source) {
  if (source == NULL || source[0] == '\0') {
    return 1;
  }
  /* PROBE_TRACE + TODO_VERIFY:
   * The early low-range synthetic experiment crashed during spawn-finalize. Keep
   * this targeted scan helper out of that stage until the original startup
   * AtomicModelInfo expansion is reproduced.
   */
  return strcmp(source, "spawn_finalize") != 0;
}

static LONG samp_asset_preload_low_range_window_compat(int32_t anchor_model, const char *source,
                                                       gta_keygen_get_uppercase_key_fn get_key,
                                                       gta_txd_find_slot_fn find_slot,
                                                       gta_txd_add_slot_fn add_slot) {
  uint32_t preload_limit = samp_asset_custom_low_preload_limit_compat();
  int32_t start_model = anchor_model + 1;
  int32_t end_model = anchor_model;
  int32_t model = 0;
  LONG registered = 0;
  LONG already_registered = 0;
  LONG skipped = 0;
  LONG store_before = -1;
  LONG store_after = -1;
  const char *stopped = "end";

  if (!object_compat_is_samp_custom_low_range_model(anchor_model) || preload_limit == 0u ||
      !samp_asset_low_preload_source_enabled_compat(source)) {
    return 0;
  }
  if (preload_limit >=
      (uint32_t)(SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MAX - SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MIN + 1)) {
    /* OBSERVED_037 + PROBE_TRACE:
     * Original R5 had the complete 11682..11753 range registered before
     * LoadCdDirectory. Make the default full-range pass independent of which
     * low custom model happens to be requested first.
     */
    start_model = SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MIN;
    end_model = SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MAX;
  } else {
    if (start_model > SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MAX) {
      return 0;
    }
    if ((uint32_t)(SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MAX - anchor_model) < preload_limit) {
      end_model = SAMP_OBJECT_COMPAT_CUSTOM_LOW_MODEL_MAX;
    } else {
      end_model = anchor_model + (int32_t)preload_limit;
    }
  }

  (void)samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &store_before);
  for (model = start_model; model <= end_model; ++model) {
    const samp_asset_model_entry_compat *model_entry = NULL;
    char asset_reason[96];
    LONG store_count = -1;
    unsigned long store_capacity = samp_asset_atomic_model_store_capacity_compat();

    if (object_compat_model_available(model)) {
      ++already_registered;
      continue;
    }
    if (samp_asset_registration_model_blocked_compat(model)) {
      ++skipped;
      continue;
    }
    model_entry = samp_asset_model_lookup_compat(model);
    if (model_entry == NULL || model_entry->section != SAMP_ASSET_IDE_SECTION_OBJS) {
      ++skipped;
      continue;
    }
    if (!samp_asset_custom_model_files_ready_compat(model, asset_reason, sizeof(asset_reason))) {
      ++skipped;
      continue;
    }
    if (!samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &store_count)) {
      stopped = "store_count_unreadable";
      break;
    }
    if (store_count >= (LONG)store_capacity) {
      stopped = "atomic_cap";
      break;
    }
    if (samp_asset_register_model_info_entry_compat(
            model_entry, (gta_model_info_add_atomic_fn)(uintptr_t)SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, get_key,
            find_slot, add_slot, source, registered < 4)) {
      ++registered;
    } else {
      ++skipped;
    }
  }
  (void)samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &store_after);

  runtime_tracef("samp_asset_registration: low_preload source=%s anchor=%ld start=%ld end=%ld limit=%lu "
                 "registered=%ld already=%ld skipped=%ld stopped=%s store=%ld->%ld env=%s "
                 "evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                 source != NULL ? source : "unknown", (long)anchor_model, (long)start_model, (long)end_model,
                 (unsigned long)preload_limit, (long)registered, (long)already_registered, (long)skipped, stopped,
                 (long)store_before, (long)store_after, SAMP_OBJECT_COMPAT_CUSTOM_LOW_PRELOAD_ENV);
  return registered;
}

static int samp_asset_register_custom_model_infos_compat(const char *source) {
  static LONG attempted = 0;
  static LONG registered_count = 0;
  gta_keygen_get_uppercase_key_fn get_key =
      (gta_keygen_get_uppercase_key_fn)(uintptr_t)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY;
  gta_txd_find_slot_fn find_slot = (gta_txd_find_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_FIND_SLOT;
  gta_txd_add_slot_fn add_slot = (gta_txd_add_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_ADD_SLOT;
  uint32_t bulk_limit = samp_asset_custom_asset_bulk_limit_compat();
  LONG registered = 0;
  LONG already_registered = 0;
  LONG skipped = 0;
  LONG considered = 0;
  LONG order_index = 0;
  LONG order_count = 0;
  LONG store_before = -1;
  LONG store_after = -1;

  if (InterlockedCompareExchange(&attempted, 0, 0) != 0) {
    return InterlockedCompareExchange(&registered_count, 0, 0) > 0;
  }
  if (bulk_limit == 0u) {
    if (InterlockedCompareExchange(&attempted, 1, 0) != 0) {
      return InterlockedCompareExchange(&registered_count, 0, 0) > 0;
    }
    runtime_tracef("samp_asset_registration: bulk_model_info_skip source=%s reason=bulk_limit_zero env=%s "
                   "indexed=%ld pending_first=1 evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                   source != NULL ? source : "unknown", SAMP_OBJECT_COMPAT_CUSTOM_ASSET_BULK_LIMIT_ENV,
                   (long)g_runtime.samp_asset_custom_model_count);
    return InterlockedCompareExchange(&registered_count, 0, 0) > 0;
  }
  if (!gta_code_ptr_compat((uintptr_t)get_key)) {
    runtime_tracef("samp_asset_registration: bulk_skip source=%s reason=bad_key_fn "
                   "key=0x%08lx evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   source != NULL ? source : "unknown", (unsigned long)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY);
    return 0;
  }
  if (InterlockedCompareExchange(&attempted, 1, 0) != 0) {
    return InterlockedCompareExchange(&registered_count, 0, 0) > 0;
  }

  order_count = g_runtime.samp_asset_model_order_count;
  if (order_count < 0) {
    order_count = 0;
  } else if (order_count > (LONG)SAMP_GTA_MODEL_INFO_COUNT) {
    order_count = (LONG)SAMP_GTA_MODEL_INFO_COUNT;
  }
  (void)samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &store_before);

  /* OBSERVED_037 + PROBE_TRACE:
   * Preserve SAMP.ide parse order. Stock R5 registers the high `objs` rows
   * first and the low 11682..11753 block last; model 11753 is the allocation
   * that advances the original AtomicModelInfo count from 15416 to 15417.
   */
  for (order_index = 0; order_index < order_count; ++order_index) {
    int32_t model = (int32_t)g_runtime.samp_asset_model_order[order_index];
    const samp_asset_model_entry_compat *model_entry = samp_asset_model_lookup_compat(model);
    int was_available = 0;
    if (model_entry == NULL) {
      continue;
    }
    if (considered >= (LONG)bulk_limit) {
      break;
    }
    ++considered;
    was_available = object_compat_model_available(model);
    if (samp_asset_register_model_info_entry_compat(model_entry,
                                                    samp_asset_model_info_add_fn_for_entry_compat(model_entry),
                                                    get_key, find_slot, add_slot, source, considered <= 24)) {
      if (was_available) {
        ++already_registered;
      } else {
        ++registered;
      }
    } else {
      ++skipped;
    }
  }

  (void)samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &store_after);
  InterlockedExchange(&registered_count, registered + already_registered);
  runtime_tracef("samp_asset_registration: bulk_model_info source=%s registered=%ld already=%ld skipped=%ld "
                 "considered=%ld limit=%lu indexed=%ld order=%ld store=%ld->%ld "
                 "evidence=OBSERVED_037,GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                 source != NULL ? source : "unknown", (long)registered, (long)already_registered, (long)skipped,
                 (long)considered, (unsigned long)bulk_limit, (long)g_runtime.samp_asset_custom_model_count,
                 (long)order_count, (long)store_before, (long)store_after);
  return (registered + already_registered) > 0;
}

static int samp_asset_full_bulk_registration_configured_compat(void) {
  LONG indexed = g_runtime.samp_asset_model_order_count;

  return samp_asset_custom_asset_bulk_enabled_compat() && samp_asset_atomic_model_store_expanded_compat() &&
         samp_asset_atomic_model_store_capacity_compat() >= SAMP_GTA_ATOMIC_MODEL_INFO_COUNT && indexed > 0 &&
         samp_asset_custom_asset_bulk_limit_compat() >= (uint32_t)indexed;
}

static int samp_asset_register_custom_model_compat(int32_t model, const char *source) {
  const samp_asset_model_entry_compat *model_entry = NULL;
  gta_keygen_get_uppercase_key_fn get_key =
      (gta_keygen_get_uppercase_key_fn)(uintptr_t)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY;
  gta_txd_find_slot_fn find_slot = (gta_txd_find_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_FIND_SLOT;
  gta_txd_add_slot_fn add_slot = (gta_txd_add_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_ADD_SLOT;
  char asset_reason[96];
  int full_bulk_first = 0;

  if (!object_compat_is_samp_custom_model(model)) {
    return object_compat_model_available(model);
  }
  if (!samp_asset_custom_asset_register_enabled_compat()) {
    runtime_tracef("samp_asset_registration: skip model=%ld source=%s reason=disabled env=%s "
                   "evidence=GTA_REVERSED_REF,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown", SAMP_OBJECT_COMPAT_CUSTOM_ASSET_REGISTER_ENV);
    return 0;
  }
  if (!object_compat_scene_ready()) {
    runtime_tracef("samp_asset_registration: defer model=%ld source=%s reason=scene_not_loaded "
                   "evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown");
    return 0;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 0, 0) == 0) {
    samp_asset_index_build_compat();
  }

  model_entry = samp_asset_model_lookup_compat(model);
  if (model_entry == NULL) {
    runtime_tracef("samp_asset_registration: skip model=%ld source=%s reason=missing_ide_entry "
                   "evidence=PROBE_TRACE,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown");
    return 0;
  }

  full_bulk_first = samp_asset_full_bulk_registration_configured_compat();
  if (full_bulk_first) {
    (void)samp_asset_register_custom_model_infos_compat(source);
  }
  if (!samp_asset_custom_model_files_ready_compat(model, asset_reason, sizeof(asset_reason))) {
    runtime_tracef("samp_asset_registration: skip model=%ld source=%s reason=%s "
                   "evidence=PROBE_TRACE,TODO_VERIFY",
                   (long)model, source != NULL ? source : "unknown",
                   asset_reason[0] != '\0' ? asset_reason : "asset_incomplete");
    return 0;
  }

  /* OBSERVED_037 + PROBE_TRACE + TODO_VERIFY:
   * With the relocated full-capacity store, the complete IDE-ordered bulk pass
   * runs first. Retain targeted-first behavior only for diagnostic builds that
   * disable the expansion or reduce the configured bulk limit.
   */
  if (!object_compat_model_available(model)) {
    (void)samp_asset_register_model_info_entry_compat(
        model_entry, samp_asset_model_info_add_fn_for_entry_compat(model_entry), get_key, find_slot, add_slot, source,
        1);
  }
  if (!full_bulk_first) {
    (void)samp_asset_preload_low_range_window_compat(model, source, get_key, find_slot, add_slot);
  }
  if (!full_bulk_first && samp_asset_custom_asset_bulk_enabled_compat()) {
    (void)samp_asset_register_custom_model_infos_compat(source);
  }
  (void)samp_asset_register_streaming_archives_compat(source, 1);
  return object_compat_model_available(model);
}

static void samp_asset_process_pending_registrations_compat(const char *source) {
  static LONG bad_fns_logged = 0;
  gta_keygen_get_uppercase_key_fn get_key =
      (gta_keygen_get_uppercase_key_fn)(uintptr_t)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY;
  gta_txd_find_slot_fn find_slot = (gta_txd_find_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_FIND_SLOT;
  gta_txd_add_slot_fn add_slot = (gta_txd_add_slot_fn)(uintptr_t)SAMP_ADDR_CTXDSTORE_ADD_SLOT;
  LONG request_seq = 0;
  LONG applied_seq = 0;
  LONG count = 0;
  LONG registered = 0;
  LONG already_registered = 0;
  LONG preloaded = 0;
  LONG skipped = 0;
  LONG i = 0;
  int archive_loaded = 0;
  int bulk_enabled = 0;
  int bulk_first = 0;
  int bulk_ok = 0;

  if (!samp_asset_custom_asset_register_enabled_compat()) {
    return;
  }
  if (!object_compat_scene_ready()) {
    return;
  }

  request_seq = InterlockedCompareExchange(&g_runtime.samp_asset_register_request_seq, 0, 0);
  applied_seq = InterlockedCompareExchange(&g_runtime.samp_asset_register_applied_seq, 0, 0);
  count = InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_count, 0, 0);
  if (count <= 0 || (request_seq == applied_seq && count <= 0)) {
    return;
  }
  if (count > (LONG)SAMP_ASSET_REGISTER_PENDING_MAX) {
    count = (LONG)SAMP_ASSET_REGISTER_PENDING_MAX;
  }

  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 0, 0) == 0) {
    samp_asset_index_build_compat();
  }
  if (!gta_code_ptr_compat((uintptr_t)get_key)) {
    if (InterlockedCompareExchange(&bad_fns_logged, 1, 0) == 0) {
      runtime_tracef("samp_asset_registration: drain_skip source=%s reason=bad_key_fn "
                     "key=0x%08lx evidence=GTA_REVERSED_REF,TODO_VERIFY",
                     source != NULL ? source : "unknown", (unsigned long)SAMP_ADDR_KEYGEN_GET_UPPERCASE_KEY);
    }
    return;
  }

  bulk_enabled = samp_asset_custom_asset_bulk_enabled_compat();
  bulk_first = samp_asset_full_bulk_registration_configured_compat();
  if (bulk_first) {
    /* OBSERVED_037 + PROBE_TRACE:
     * The full stock Atomic catalog fits the relocated store exactly. Register
     * it in IDE order before draining server-requested IDs so every ModelInfo
     * exists before the first archive directory pass.
     */
    bulk_ok = samp_asset_register_custom_model_infos_compat(source);
  }

  for (i = 0; i < count; ++i) {
    int32_t model = (int32_t)InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_models[i], 0, 0);
    const samp_asset_model_entry_compat *model_entry = NULL;
    char asset_reason[96];

    InterlockedExchange(&g_runtime.samp_asset_register_pending_models[i], 0);
    if (!object_compat_is_samp_custom_model(model)) {
      continue;
    }
    if (object_compat_model_available(model)) {
      ++already_registered;
      continue;
    }
    model_entry = samp_asset_model_lookup_compat(model);
    if (model_entry == NULL) {
      ++skipped;
      runtime_tracef("samp_asset_registration: drain_skip model=%ld source=%s reason=missing_ide_entry "
                     "evidence=PROBE_TRACE,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown");
      continue;
    }
    if (!samp_asset_custom_model_files_ready_compat(model, asset_reason, sizeof(asset_reason))) {
      ++skipped;
      runtime_tracef("samp_asset_registration: drain_skip model=%ld source=%s reason=%s "
                     "evidence=PROBE_TRACE,TODO_VERIFY",
                     (long)model, source != NULL ? source : "unknown",
                     asset_reason[0] != '\0' ? asset_reason : "asset_incomplete");
      continue;
    }
    if (samp_asset_register_model_info_entry_compat(model_entry,
                                                    samp_asset_model_info_add_fn_for_entry_compat(model_entry),
                                                    get_key, find_slot, add_slot, source, 1)) {
      ++registered;
      preloaded += samp_asset_preload_low_range_window_compat(model, source, get_key, find_slot, add_slot);
    } else {
      ++skipped;
    }
  }

  if (bulk_enabled && !bulk_first) {
    bulk_ok = samp_asset_register_custom_model_infos_compat(source);
  }

  if (registered > 0 || already_registered > 0 || preloaded > 0 || bulk_enabled) {
    archive_loaded = samp_asset_register_streaming_archives_compat(source, registered > 0 || preloaded > 0 || bulk_ok);
  }
  InterlockedExchange(&g_runtime.samp_asset_register_pending_count, 0);
  InterlockedExchange(&g_runtime.samp_asset_register_applied_seq, request_seq);
  runtime_tracef("samp_asset_registration: drain source=%s request_seq=%ld count=%ld registered=%ld already=%ld "
                 "preloaded=%ld skipped=%ld bulk_first=%d bulk_ok=%d archives=%d pending=%ld "
                 "evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                 source != NULL ? source : "unknown", (long)request_seq, (long)count, (long)registered,
                 (long)already_registered, (long)preloaded, (long)skipped, bulk_first, bulk_ok, archive_loaded,
                 (long)InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_count, 0, 0));
  object_compat_flush_pending(object_compat_create_budget());
}

static void samp_asset_warm_custom_assets_compat(const char *source) {
  int bulk_ok = 0;
  int archives = 0;
  LONG pending = 0;

  if (!samp_asset_custom_asset_register_enabled_compat() || !object_compat_scene_ready()) {
    return;
  }
  if (!samp_asset_custom_asset_bulk_enabled_compat()) {
    return;
  }
  pending = InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_count, 0, 0);
  if (pending > 0) {
    runtime_tracef("samp_asset_registration: warm_defer source=%s reason=pending_first pending=%ld "
                   "evidence=PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                   source != NULL ? source : "unknown", (long)pending);
    return;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 0, 0) == 0) {
    samp_asset_index_build_compat();
  }

  bulk_ok = samp_asset_register_custom_model_infos_compat(source);
  archives = samp_asset_register_streaming_archives_compat(source, bulk_ok);
  runtime_tracef("samp_asset_registration: warm source=%s bulk_ok=%d archives=%d custom_models=%ld "
                 "pending=%ld evidence=OBSERVED_037,PROBE_TRACE,GTA_REVERSED_REF,TODO_VERIFY",
                 source != NULL ? source : "unknown", bulk_ok, archives,
                 (long)InterlockedCompareExchange(&g_runtime.samp_asset_custom_model_count, 0, 0),
                 (long)InterlockedCompareExchange(&g_runtime.samp_asset_register_pending_count, 0, 0));
}

static int samp_asset_custom_proxy_enabled_compat(void) {
  static LONG initialized = 0;
  static int enabled = 0;
  const char *value = NULL;

  if (InterlockedCompareExchange(&initialized, 0, 0)) {
    return enabled;
  }

  value = getenv(SAMP_OBJECT_COMPAT_CUSTOM_PROXY_ENV);
  if (value != NULL && value[0] == '1' && value[1] == '\0') {
    enabled = 1;
  }
  InterlockedExchange(&initialized, 1);
  return enabled;
}

static int local_spawn_skin_apply_enabled_compat(void) {
  static LONG initialized = 0;
  static int enabled = 0;
  const char *value = NULL;

  if (InterlockedCompareExchange(&initialized, 0, 0)) {
    return enabled;
  }

  value = getenv(SAMP_LOCAL_SPAWN_SKIN_APPLY_ENV);
  if (value != NULL && value[0] == '1' && value[1] == '\0') {
    enabled = 1;
  }
  InterlockedExchange(&initialized, 1);
  return enabled;
}

static int class_selection_skin_apply_enabled_compat(void) {
  static LONG initialized = 0;
  static int enabled = 1;
  const char *value = NULL;

  if (InterlockedCompareExchange(&initialized, 0, 0)) {
    return enabled;
  }

  value = getenv(SAMP_CLASS_SELECTION_SKIN_APPLY_ENV);
  if (value != NULL && value[0] != '\0') {
    enabled = value[0] != '0' && value[0] != 'n' && value[0] != 'N' && value[0] != 'f' && value[0] != 'F';
  }
  InterlockedExchange(&initialized, 1);
  return enabled;
}

static int samp_asset_custom_proxy_model_compat(int32_t model, int32_t *out_model, char *reason,
                                                size_t reason_size) {
  const samp_asset_model_entry_compat *model_entry = NULL;
  char asset_reason[96];
  int32_t proxy_model = SAMP_OBJECT_COMPAT_CUSTOM_PROXY_MODEL;

  if (reason != NULL && reason_size != 0u) {
    reason[0] = '\0';
  }
  if (out_model != NULL) {
    *out_model = model;
  }
  if (!object_compat_is_samp_custom_model(model)) {
    if (reason != NULL && reason_size != 0u) {
      snprintf(reason, reason_size, "not_samp_custom_model");
    }
    return 0;
  }
  if (object_compat_model_available(model)) {
    if (reason != NULL && reason_size != 0u) {
      snprintf(reason, reason_size, "native_registered");
    }
    return 0;
  }
  if (!samp_asset_custom_proxy_enabled_compat()) {
    if (reason != NULL && reason_size != 0u) {
      snprintf(reason, reason_size, "proxy_disabled");
    }
    return 0;
  }

  model_entry = samp_asset_model_lookup_compat(model);
  if (model_entry == NULL) {
    if (reason != NULL && reason_size != 0u) {
      snprintf(reason, reason_size, "missing_ide_entry");
    }
    return 0;
  }
  if (!object_compat_model_available(proxy_model)) {
    if (reason != NULL && reason_size != 0u) {
      snprintf(reason, reason_size, "proxy_model_unavailable:%ld", (long)proxy_model);
    }
    return 0;
  }

  (void)samp_asset_custom_model_files_ready_compat(model, asset_reason, sizeof(asset_reason));
  if (out_model != NULL) {
    *out_model = proxy_model;
  }
  if (reason != NULL && reason_size != 0u) {
    snprintf(reason, reason_size, "proxy:%ld asset=%s", (long)proxy_model,
             asset_reason[0] != '\0' ? asset_reason : "unknown");
  }
  return 1;
}

static const char *samp_asset_custom_model_skip_reason_compat(int32_t model) {
  char reason[96];

  if (!object_compat_is_samp_custom_model(model)) {
    return NULL;
  }
  if (!samp_asset_custom_model_files_ready_compat(model, reason, sizeof(reason))) {
    return "samp_custom_model_asset_incomplete";
  }
  if (samp_asset_registration_model_blocked_compat(model)) {
    return "samp_custom_model_registration_blocked";
  }
  if (!object_compat_model_available(model)) {
    return "samp_custom_model_unregistered";
  }
  return NULL;
}

static void samp_asset_model_describe_compat(int32_t model, char *out, size_t out_size) {
  const samp_asset_model_entry_compat *model_entry = NULL;
  char dff_name[SAMP_ASSET_NAME_BYTES + 8u];
  char txd_name[SAMP_ASSET_NAME_BYTES + 8u];
  char dff_state[64];
  char txd_state[64];
  char sampcol_state[64];

  if (out == NULL || out_size == 0u) {
    return;
  }
  out[0] = '\0';
  model_entry = samp_asset_model_lookup_compat(model);
  if (model_entry == NULL) {
    snprintf(out, out_size, " asset=missing_index index_built=%ld", (long)g_runtime.samp_asset_index_built);
    return;
  }

  samp_asset_make_ext_name_compat(dff_name, sizeof(dff_name), model_entry->model_name, "dff");
  samp_asset_make_ext_name_compat(txd_name, sizeof(txd_name),
                                  model_entry->txd_name[0] != '\0' ? model_entry->txd_name : model_entry->model_name,
                                  "txd");
  samp_asset_describe_file_compat(dff_state, sizeof(dff_state), dff_name);
  samp_asset_describe_file_compat(txd_state, sizeof(txd_state), txd_name);
  samp_asset_describe_file_compat(sampcol_state, sizeof(sampcol_state), SAMP_ASSET_ALL_SAMPCOLS_NAME);

  snprintf(out, out_size,
           " asset=present source=%s section=%s name='%s' txd='%s' draw=%.3f flags=0x%08lx "
           "dff=%s txd_file=%s sampcol=%s",
           samp_asset_ide_source_label_compat(model_entry->source),
           samp_asset_section_label_compat(model_entry->section), model_entry->model_name, model_entry->txd_name,
           (double)model_entry->draw_distance, (unsigned long)model_entry->flags, dff_state, txd_state,
           sampcol_state);
}

static void samp_asset_log_interesting_models_compat(void) {
  static const int32_t interesting_models[] = {11692, 18631, 18779, 18783, 18830, 18980, 19128, 19325,
                                               19379, 19435, 19894, 19901};
  size_t i = 0u;

  for (i = 0u; i < sizeof(interesting_models) / sizeof(interesting_models[0]); ++i) {
    char description[320];
    int32_t model = interesting_models[i];
    samp_asset_model_describe_compat(model, description, sizeof(description));
    runtime_tracef("samp_asset_model: model=%ld%s evidence=PROBE_TRACE,TODO_VERIFY", (long)model, description);
  }
}

static void samp_asset_log_custom_model_gate_compat(void) {
  LONG indexed = 0;
  LONG assets_ready_count = 0;
  LONG asset_incomplete_count = 0;
  LONG registered_count = 0;
  LONG sample_count = 0;
  int32_t model = 0;

  for (model = 0; model < (int32_t)SAMP_GTA_MODEL_INFO_COUNT; ++model) {
    const samp_asset_model_entry_compat *model_entry = samp_asset_model_lookup_compat(model);
    char description[320];
    char asset_reason[96];
    int assets_ready = 0;
    uintptr_t model_info = 0u;

    if (model_entry == NULL) {
      continue;
    }

    ++indexed;
    assets_ready = samp_asset_custom_model_files_ready_compat(model, asset_reason, sizeof(asset_reason));
    if (assets_ready) {
      ++assets_ready_count;
    } else {
      ++asset_incomplete_count;
    }

    model_info = object_compat_model_info_ptr(model);
    if (model_info != 0u) {
      ++registered_count;
    }

    if (sample_count < 24 || model_info != 0u) {
      samp_asset_model_describe_compat(model, description, sizeof(description));
      runtime_tracef("samp_asset_custom_gate: model=%ld gate=all_indexed assets_ready=%d asset_reason=%s "
                     "model_info=0x%08lx%s evidence=PROBE_TRACE,INFERRED,TODO_VERIFY",
                     (long)model, assets_ready, asset_reason[0] != '\0' ? asset_reason : "unknown",
                     (unsigned long)model_info, description);
      ++sample_count;
    }
  }

  runtime_tracef("samp_asset_custom_gate: summary gate=all_indexed indexed=%ld assets_ready=%ld "
                 "asset_incomplete=%ld registered=%ld samples=%ld evidence=PROBE_TRACE,INFERRED,TODO_VERIFY",
                 (long)indexed, (long)assets_ready_count, (long)asset_incomplete_count, (long)registered_count,
                 (long)sample_count);
}

static void samp_asset_index_build_compat(void) {
  if (InterlockedCompareExchange(&g_runtime.samp_asset_index_built, 1, 0) != 0) {
    return;
  }

  /* OBSERVED_037 + PROBE_TRACE + TODO_VERIFY:
   * Original R5 loads these SA-MP asset sidecars before custom object use. This
   * index is diagnostic only; it must not make custom IDs visible to GTA until
   * CModelInfo/streaming registration is separately validated.
   */
  memset(g_runtime.samp_asset_models, 0, sizeof(g_runtime.samp_asset_models));
  memset(g_runtime.samp_asset_model_order, 0, sizeof(g_runtime.samp_asset_model_order));
  memset(g_runtime.samp_asset_img_entries, 0, sizeof(g_runtime.samp_asset_img_entries));
  memset(g_runtime.samp_asset_register_blocked_models, 0, sizeof(g_runtime.samp_asset_register_blocked_models));
  g_runtime.samp_asset_model_count = 0;
  g_runtime.samp_asset_model_order_count = 0;
  g_runtime.samp_asset_custom_model_count = 0;
  g_runtime.samp_asset_img_entry_count = 0;
  g_runtime.samp_asset_col_entry_count = 0;

  samp_asset_parse_ide_compat("samp_ide", "SAMP\\samp.IDE", SAMP_ASSET_IDE_SOURCE_SAMP);
  samp_asset_parse_ide_compat("custom_ide", "SAMP\\custom.IDE", SAMP_ASSET_IDE_SOURCE_CUSTOM);
  samp_asset_parse_img_compat("samp_img", "SAMP\\SAMP.IMG", SAMP_ASSET_ARCHIVE_SAMP_IMG);
  samp_asset_parse_img_compat("custom_img", "SAMP\\CUSTOM.IMG", SAMP_ASSET_ARCHIVE_CUSTOM_IMG);
  samp_asset_parse_img_compat("sampcol_img", "SAMP\\SAMPCOL.IMG", SAMP_ASSET_ARCHIVE_SAMPCOL_IMG);

  runtime_tracef("samp_asset_index: summary models=%ld model_order=%ld custom_models=%ld img_entries=%ld col_entries=%ld "
                 "evidence=OBSERVED_037,PROBE_TRACE,TODO_VERIFY",
                 (long)g_runtime.samp_asset_model_count, (long)g_runtime.samp_asset_model_order_count,
                 (long)g_runtime.samp_asset_custom_model_count, (long)g_runtime.samp_asset_img_entry_count,
                 (long)g_runtime.samp_asset_col_entry_count);
  samp_asset_log_interesting_models_compat();
  samp_asset_log_custom_model_gate_compat();
}

static int resolve_module_proc(HMODULE *module_slot, const char *module_name, const char *proc_name, FARPROC *out_proc) {
  HMODULE module_handle = NULL;
  FARPROC proc = NULL;

  if (module_slot == NULL || module_name == NULL || proc_name == NULL || out_proc == NULL) {
    return 0;
  }

  module_handle = *module_slot;
  if (module_handle == NULL) {
    module_handle = GetModuleHandleA(module_name);
    if (module_handle == NULL) {
      module_handle = LoadLibraryA(module_name);
    }
    *module_slot = module_handle;
  }
  if (module_handle == NULL) {
    return 0;
  }

  proc = GetProcAddress(module_handle, proc_name);
  if (proc == NULL) {
    return 0;
  }

  *out_proc = proc;
  return 1;
}

static void copy_cmd_token(const char *src, char *dst, size_t dst_size) {
  size_t i = 0;

  if (dst == NULL || dst_size == 0) {
    return;
  }

  dst[0] = '\0';
  if (src == NULL) {
    return;
  }

  while (*src == ' ') {
    ++src;
  }

  while (*src != '\0' && *src != ' ' && *src != '-' && *src != '/' && i + 1 < dst_size) {
    dst[i++] = *src++;
  }
  dst[i] = '\0';
}

static int parse_u16(const char *text, uint16_t *out) {
  unsigned long value = 0;
  size_t i = 0;

  if (text == NULL || *text == '\0' || out == NULL) {
    return 0;
  }

  for (i = 0; text[i] != '\0'; ++i) {
    char c = text[i];
    if (c < '0' || c > '9') {
      return 0;
    }
    value = (value * 10UL) + (unsigned long)(c - '0');
    if (value > 65535UL) {
      return 0;
    }
  }

  *out = (uint16_t)value;
  return 1;
}

static int parse_u32(const char *text, uint32_t *out) {
  unsigned long value = 0;
  char *endptr = NULL;

  if (text == NULL || *text == '\0' || out == NULL) {
    return 0;
  }

  value = strtoul(text, &endptr, 10);
  if (endptr == text || *endptr != '\0') {
    return 0;
  }
  if (value > 0xFFFFFFFFUL) {
    return 0;
  }
  *out = (uint32_t)value;
  return 1;
}

static DWORD preconnect_delay_ms_compat(void) {
  static LONG initialized = 0;
  static DWORD delay_ms = SAMP_PRECONNECT_DELAY_MS;
  const char *value = NULL;
  uint32_t parsed = 0;

  if (InterlockedCompareExchange(&initialized, 0, 0)) {
    return delay_ms;
  }

  value = getenv("SAMPDLL_PRECONNECT_DELAY_MS");
  if (parse_u32(value, &parsed) && parsed <= 30000u) {
    delay_ms = (DWORD)parsed;
  }
  InterlockedExchange(&initialized, 1);
  return delay_ms;
}

static const char *raknet_packet_name(int packet_id) {
  switch (packet_id) {
    case 12:
      return "ID_AUTH_KEY";
    case 20:
      return "ID_RPC";
    case 24:
      return "ID_OPEN_CONNECTION_REQUEST";
    case 25:
      return "ID_OPEN_CONNECTION_REPLY";
    case 26:
      return "ID_OPEN_CONNECTION_COOKIE";
    case 28:
      return "ID_RSA_PUBLIC_KEY_MISMATCH";
    case 29:
      return "ID_CONNECTION_ATTEMPT_FAILED";
    case 30:
      return "ID_NEW_INCOMING_CONNECTION";
    case 31:
      return "ID_NO_FREE_INCOMING_CONNECTIONS";
    case 32:
      return "ID_DISCONNECTION_NOTIFICATION";
    case 33:
      return "ID_CONNECTION_LOST";
    case 34:
      return "ID_CONNECTION_REQUEST_ACCEPTED";
    case 36:
      return "ID_CONNECTION_BANNED";
    case 37:
      return "ID_INVALID_PASSWORD";
    case 38:
      return "ID_MODIFIED_PACKET";
    default:
      return "UNKNOWN";
  }
}

static void chat_add_connect_retry_message_compat(int packet_id, const char *reason) {
  const char *message = "The server didn't respond. Retrying..";

  /*
   * STATIC_037 + INFERRED:
   * Original 0.3.7 CNetGame packet handlers put these exact debug strings into the chat window
   * and then return to GAMESTATE_WAIT_CONNECT, letting the normal retry timer reconnect.
   */
  if (packet_id == 31) {
    message = "The server is full. Retrying...";
  } else if (packet_id == 33) {
    message = "Lost connection to the server. Reconnecting..";
  }

  chat_compat_add_message("%s", message);
  runtime_tracef("network_prepare: connect retry chat reason=%s packet=%d message='%s' evidence=STATIC_037,INFERRED",
                 reason != NULL ? reason : "unknown", packet_id, message);
}

static void copy_runtime_token(const char *src, char *dst, size_t dst_size) {
  size_t i = 0;

  if (dst == NULL || dst_size == 0) {
    return;
  }
  dst[0] = '\0';
  if (src == NULL) {
    return;
  }

  while (src[i] != '\0' && i + 1 < dst_size) {
    dst[i] = src[i];
    ++i;
  }
  dst[i] = '\0';
}

static void configure_raknet_join_profile_once(void) {
  const char *nickname_env = getenv("SAMPDLL_NICKNAME");
  const char *version_env = getenv("SAMPDLL_CLIENT_VERSION");
  const char *netgame_version_env = getenv("SAMPDLL_NETGAME_VERSION");
  const char *client_mod_env = getenv("SAMPDLL_CLIENT_MOD");
  uint32_t netgame_version = SAMP_DEFAULT_NETGAME_VERSION;
  uint16_t client_mod = SAMP_DEFAULT_CLIENT_MOD;

  if (InterlockedCompareExchange(&g_runtime.raknet_profile_ready, 1, 0) != 0) {
    return;
  }

  memset(&g_runtime.raknet_join_profile, 0, sizeof(g_runtime.raknet_join_profile));

  if (nickname_env != NULL && nickname_env[0] != '\0') {
    copy_runtime_token(nickname_env, g_runtime.raknet_join_profile.nickname, sizeof(g_runtime.raknet_join_profile.nickname));
  } else if (g_runtime.settings.nickname[0] != '\0') {
    copy_runtime_token(g_runtime.settings.nickname, g_runtime.raknet_join_profile.nickname,
                       sizeof(g_runtime.raknet_join_profile.nickname));
  } else {
    copy_runtime_token(SAMP_DEFAULT_NICKNAME, g_runtime.raknet_join_profile.nickname,
                       sizeof(g_runtime.raknet_join_profile.nickname));
  }

  if (version_env != NULL && version_env[0] != '\0') {
    copy_runtime_token(version_env, g_runtime.raknet_join_profile.client_version,
                       sizeof(g_runtime.raknet_join_profile.client_version));
  } else {
    copy_runtime_token(SAMP_DEFAULT_CLIENT_VERSION, g_runtime.raknet_join_profile.client_version,
                       sizeof(g_runtime.raknet_join_profile.client_version));
  }

  if (parse_u32(netgame_version_env, &netgame_version)) {
    g_runtime.raknet_join_profile.netgame_version = netgame_version;
  } else {
    g_runtime.raknet_join_profile.netgame_version = SAMP_DEFAULT_NETGAME_VERSION;
  }

  if (parse_u16(client_mod_env, &client_mod) && client_mod <= 255u) {
    g_runtime.raknet_join_profile.mod_byte = (uint8_t)client_mod;
  } else {
    g_runtime.raknet_join_profile.mod_byte = (uint8_t)SAMP_DEFAULT_CLIENT_MOD;
  }

  runtime_tracef("raknet_profile: nick='%s' version='%s' netver=%lu mod=%u", g_runtime.raknet_join_profile.nickname,
                 g_runtime.raknet_join_profile.client_version, (unsigned long)g_runtime.raknet_join_profile.netgame_version,
                 (unsigned)g_runtime.raknet_join_profile.mod_byte);
}

static void load_settings_from_command_line(samp_game_settings *settings) {
  char *cursor = GetCommandLineA();

  if (settings == NULL) {
    return;
  }
  memset(settings, 0, sizeof(*settings));

  if (cursor == NULL) {
    return;
  }

  while (*cursor != '\0') {
    if (*cursor == '-' || *cursor == '/') {
      ++cursor;
      switch (*cursor) {
        case 'd':
          settings->debug = TRUE;
          settings->play_online = FALSE;
          break;
        case 'c':
          settings->play_online = TRUE;
          settings->debug = FALSE;
          break;
        case 'w':
          settings->windowed_mode = TRUE;
          break;
        case 'z':
          ++cursor;
          copy_cmd_token(cursor, settings->connect_pass, sizeof(settings->connect_pass));
          break;
        case 'h':
          ++cursor;
          copy_cmd_token(cursor, settings->connect_host, sizeof(settings->connect_host));
          break;
        case 'p':
          ++cursor;
          copy_cmd_token(cursor, settings->connect_port, sizeof(settings->connect_port));
          break;
        case 'n':
          ++cursor;
          copy_cmd_token(cursor, settings->nickname, sizeof(settings->nickname));
          break;
        default:
          break;
      }
    }

    if (*cursor == '\0') {
      break;
    }
    ++cursor;
  }
}

static LONG resolve_initial_entry_gate(void) {
  const char *env_value = getenv("SAMPDLL_ENTRY_GATE");
  char *endptr = NULL;
  long parsed = 0;

  if (env_value == NULL || *env_value == '\0') {
    return SAMP_ENTRY_GATE_READY;
  }

  parsed = strtol(env_value, &endptr, 10);
  if (endptr == env_value || *endptr != '\0') {
    return SAMP_ENTRY_GATE_READY;
  }
  if (parsed < 0 || parsed > 255) {
    return SAMP_ENTRY_GATE_READY;
  }
  return (LONG)parsed;
}

static LONG read_game_entry_gate_value(void) {
  return *(volatile LONG *)(uintptr_t)SAMP_ADDR_ENTRY;
}

static uint8_t read_game_u8(uintptr_t addr) {
  return *(volatile uint8_t *)(uintptr_t)addr;
}

static void write_game_u8(uintptr_t addr, uint8_t value) {
  *(volatile uint8_t *)(uintptr_t)addr = value;
}

static uint8_t gta_apply_disable_enter_exits_compat(int disable_enter_exits, const char *reason) {
  /*
   * STATIC_037:
   * InitGame only touches GTA's enter/exit byte when the server-side
   * DisableInteriorEnterExits flag is set. When the flag is clear, the
   * original path leaves GTA's current state alone.
   */
  if (disable_enter_exits != 0) {
    write_game_u8(SAMP_ADDR_ENTER_EXITS, 0u);
  }
  runtime_tracef("enter_exits: disabled=%d touched=%d gta_byte=%u reason=%s evidence=STATIC_037,PROBE_TRACE",
                 disable_enter_exits != 0 ? 1 : 0, disable_enter_exits != 0 ? 1 : 0,
                 (unsigned)read_game_u8(SAMP_ADDR_ENTER_EXITS), reason != NULL ? reason : "unknown");
  return read_game_u8(SAMP_ADDR_ENTER_EXITS);
}

static void write_game_float_compat(uintptr_t addr, float value) {
  memcpy((void *)(uintptr_t)addr, &value, sizeof(value));
}

static int read_game_u8_checked_compat(uintptr_t addr, uint8_t *value) {
  if (value == NULL || !memory_is_readable_compat((const void *)(uintptr_t)addr, sizeof(*value))) {
    return 0;
  }
  *value = read_game_u8(addr);
  return 1;
}

static int read_game_u16_checked_compat(uintptr_t addr, uint16_t *value) {
  if (value == NULL || !memory_is_readable_compat((const void *)(uintptr_t)addr, sizeof(*value))) {
    return 0;
  }
  memcpy(value, (const void *)(uintptr_t)addr, sizeof(*value));
  return 1;
}

static int read_game_u32_checked_compat(uintptr_t addr, uint32_t *value) {
  if (value == NULL || !memory_is_readable_compat((const void *)(uintptr_t)addr, sizeof(*value))) {
    return 0;
  }
  memcpy(value, (const void *)(uintptr_t)addr, sizeof(*value));
  return 1;
}

static int read_game_float_checked_compat(uintptr_t addr, float *value) {
  if (value == NULL || !memory_is_readable_compat((const void *)(uintptr_t)addr, sizeof(*value))) {
    return 0;
  }
  memcpy(value, (const void *)(uintptr_t)addr, sizeof(*value));
  return 1;
}

static int restore_post_spawn_mouse_camera_compat(const char *reason) {
  uint8_t use_mouse_before = 0xffu;
  uint8_t use_mouse_after = 0xffu;
  float accel_h_before = 0.0f;
  float accel_v_before = 0.0f;
  float accel_h_after = 0.0f;
  float accel_v_after = 0.0f;
  int changed = 0;

  if (!read_game_u8_checked_compat(SAMP_ADDR_CAMERA_USE_MOUSE_3RD_PERSON, &use_mouse_before) ||
      !read_game_float_checked_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_HORIZONTAL, &accel_h_before) ||
      !read_game_float_checked_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_VERTICAL, &accel_v_before)) {
    runtime_tracef("mp_session_bridge: mouse_camera_restore reason=%s readable=0 "
                   "evidence=GTA_REVERSED_REF,PROBE_TRACE,TODO_VERIFY",
                   reason != NULL ? reason : "unknown");
    return 0;
  }

  /*
   * GTA_REVERSED_REF + PROBE_TRACE + INFERRED + TODO_VERIFY:
   * Plugin-SDK/gta-reversed identify these CCamera fields as the third-person
   * mouse-camera enable byte and mouse acceleration floats. The current run has
   * gameplay camera mode 4 after spawn, but mouse deltas still do not rotate the
   * camera; keep this repair scoped to the post-spawn handoff.
   */
  if (use_mouse_before == 0u) {
    write_game_u8(SAMP_ADDR_CAMERA_USE_MOUSE_3RD_PERSON, 1u);
    changed = 1;
  }
  if (!isfinite(accel_h_before) || accel_h_before <= 0.0f || accel_h_before > 1.0f) {
    write_game_float_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_HORIZONTAL, SAMP_GTA_CAMERA_MOUSE_ACCEL_DEFAULT);
    changed = 1;
  }
  if (!isfinite(accel_v_before) || accel_v_before <= 0.0f || accel_v_before > 1.0f) {
    write_game_float_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_VERTICAL, SAMP_GTA_CAMERA_MOUSE_ACCEL_DEFAULT);
    changed = 1;
  }

  (void)read_game_u8_checked_compat(SAMP_ADDR_CAMERA_USE_MOUSE_3RD_PERSON, &use_mouse_after);
  (void)read_game_float_checked_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_HORIZONTAL, &accel_h_after);
  (void)read_game_float_checked_compat(SAMP_ADDR_CAMERA_MOUSE_ACCEL_VERTICAL, &accel_v_after);
  runtime_tracef("mp_session_bridge: mouse_camera_restore reason=%s use_mouse=%u->%u accel_h=%.6f->%.6f "
                 "accel_v=%.6f->%.6f changed=%d evidence=GTA_REVERSED_REF,PROBE_TRACE,INFERRED,TODO_VERIFY",
                 reason != NULL ? reason : "unknown", (unsigned)use_mouse_before, (unsigned)use_mouse_after,
                 (double)accel_h_before, (double)accel_h_after, (double)accel_v_before, (double)accel_v_after,
                 changed);
  return changed;
}

static int read_camera_mode_compat(uint8_t *mode, uint16_t *mode2) {
  uint8_t local_mode = 0xffu;
  uint16_t local_mode2 = 0xffffu;

  if (!read_game_u8_checked_compat(SAMP_ADDR_CAMERA_MODE, &local_mode)) {
    return 0;
  }
  if (!read_game_u16_checked_compat(SAMP_ADDR_CAMERA_MODE2, &local_mode2)) {
    return 0;
  }
  if (mode != NULL) {
    *mode = local_mode;
  }
  if (mode2 != NULL) {
    *mode2 = local_mode2;
  }
  return 1;
}

static void log_camera_mode_compat(const char *reason) {
  uint8_t mode = 0xffu;
  uint16_t mode2 = 0xffffu;

  if (!read_camera_mode_compat(&mode, &mode2)) {
    runtime_tracef("mp_session_bridge: camera_mode reason=%s readable=0 evidence=PROBE_TRACE,TODO_VERIFY",
                   reason != NULL ? reason : "unknown");
    return;
  }
  runtime_tracef("mp_session_bridge: camera_mode reason=%s mode=%u mode2=%u evidence=PROBE_TRACE,TODO_VERIFY",
                 reason != NULL ? reason : "unknown", (unsigned)mode, (unsigned)mode2);
}

static int restore_post_spawn_camera_mode_compat(const char *reason) {
  uint8_t before = 0xffu;
  uint8_t after = 0xffu;
  uint16_t mode2 = 0xffffu;

  if (!read_camera_mode_compat(&before, &mode2)) {
    runtime_tracef("mp_session_bridge: camera_mode_restore reason=%s readable=0 evidence=PROBE_TRACE,TODO_VERIFY",
                   reason != NULL ? reason : "unknown");
    return 0;
  }

  /*
   * PROBE_TRACE + STATIC_037 + INFERRED + TODO_VERIFY:
   * Ghidra headless shows original samp.dll dispatching restore/set/point
   * camera script opcodes around samp.dll+0x000b3e20. Probe logs show the
   * GTA camera mode byte at 0x00b6f1a8 moving between 15 during frontend
   * camera ownership and 4 during gameplay/free mouse-look.
   */
  if (before == SAMP_GTA_CAMERA_MODE_FRONTEND_FIXED) {
    write_game_u8(SAMP_ADDR_CAMERA_MODE, SAMP_GTA_CAMERA_MODE_GAMEPLAY);
    (void)read_game_u8_checked_compat(SAMP_ADDR_CAMERA_MODE, &after);
    runtime_tracef("mp_session_bridge: camera_mode_restore reason=%s mode=%u->%u mode2=%u "
                   "evidence=PROBE_TRACE,STATIC_037,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before, (unsigned)after, (unsigned)mode2);
    return 1;
  }

  runtime_tracef("mp_session_bridge: camera_mode_restore reason=%s mode=%u keep=1 mode2=%u "
                 "evidence=PROBE_TRACE,STATIC_037,INFERRED,TODO_VERIFY",
                 reason != NULL ? reason : "unknown", (unsigned)before, (unsigned)mode2);
  return 0;
}

static int patch_nop(uintptr_t addr, size_t size) {
  DWORD old_protect = 0;
  DWORD old_protect_restore = 0;

  if (addr == 0u || size == 0u) {
    return 0;
  }
  if (!VirtualProtect((LPVOID)addr, size, PAGE_EXECUTE_READWRITE, &old_protect)) {
    return 0;
  }
  memset((void *)addr, 0x90, size);
  FlushInstructionCache(GetCurrentProcess(), (LPCVOID)addr, size);
  (void)VirtualProtect((LPVOID)addr, size, old_protect, &old_protect_restore);
  return 1;
}

static int patch_copy(uintptr_t addr, const void *src, size_t size) {
  DWORD old_protect = 0;
  DWORD old_protect_restore = 0;

  if (addr == 0u || src == NULL || size == 0u) {
    return 0;
  }
  if (!VirtualProtect((LPVOID)addr, size, PAGE_EXECUTE_READWRITE, &old_protect)) {
    return 0;
  }
  memcpy((void *)addr, src, size);
  FlushInstructionCache(GetCurrentProcess(), (LPCVOID)addr, size);
  (void)VirtualProtect((LPVOID)addr, size, old_protect, &old_protect_restore);
  return 1;
}

static int apply_wanted_level_patch_compat(uint8_t level, const char *reason) {
  static const uint8_t original[SAMP_WANTED_LEVEL_PATCH_SIZE] = {
      0x83u, 0xFEu, 0x05u, 0x0Fu, 0x84u, 0xDAu, 0x00u, 0x00u, 0x00u};
  uint8_t current[SAMP_WANTED_LEVEL_PATCH_SIZE];
  uint8_t patch[SAMP_WANTED_LEVEL_PATCH_SIZE] = {
      0xBDu, 0x00u, 0x00u, 0x00u, 0x00u, 0x90u, 0x90u, 0x90u, 0x90u};
  int original_match = 0;
  int patched_match = 0;
  int applied = 0;

  if (!memory_is_readable_compat((const void *)(uintptr_t)SAMP_ADDR_WANTED_LEVEL_PATCH,
                                 sizeof(current))) {
    runtime_tracef("wanted_level_patch: skip reason=%s address_unreadable=1 evidence=STATIC_037",
                   reason != NULL ? reason : "unknown");
    return 0;
  }
  memcpy(current, (const void *)(uintptr_t)SAMP_ADDR_WANTED_LEVEL_PATCH, sizeof(current));
  original_match = memcmp(current, original, sizeof(original)) == 0;
  patched_match = current[0] == 0xBDu && current[2] == 0x00u && current[3] == 0x00u &&
                  current[4] == 0x00u && current[5] == 0x90u && current[6] == 0x90u &&
                  current[7] == 0x90u && current[8] == 0x90u;
  if (!original_match && !patched_match) {
    runtime_tracef("wanted_level_patch: skip reason=%s target_bytes_mismatch=1 first=0x%02x "
                   "evidence=STATIC_037,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)current[0]);
    return 0;
  }

  if (original_match && g_runtime.wanted_level_patch_owned == 0u) {
    memcpy(g_runtime.wanted_level_patch_saved, current, sizeof(current));
    g_runtime.wanted_level_patch_owned = 1u;
  }
  patch[1] = level;
  applied = patch_copy(SAMP_ADDR_WANTED_LEVEL_PATCH, patch, sizeof(patch));
  runtime_tracef("wanted_level_patch: %s reason=%s level=%u addr=0x%08lx original=%d already_patched=%d "
                 "original_bytes=83fe050f84da000000 patch_bytes=bd%02x00000090909090 "
                 "evidence=STATIC_037",
                 applied ? "apply" : "failed", reason != NULL ? reason : "unknown", (unsigned)level,
                 (unsigned long)SAMP_ADDR_WANTED_LEVEL_PATCH, original_match, patched_match, (unsigned)level);
  return applied;
}

static void restore_wanted_level_patch_compat(void) {
  uint8_t current[SAMP_WANTED_LEVEL_PATCH_SIZE];

  if (g_runtime.wanted_level_patch_owned == 0u ||
      !memory_is_readable_compat((const void *)(uintptr_t)SAMP_ADDR_WANTED_LEVEL_PATCH, sizeof(current))) {
    return;
  }
  memcpy(current, (const void *)(uintptr_t)SAMP_ADDR_WANTED_LEVEL_PATCH, sizeof(current));
  if (current[0] == 0xBDu && current[2] == 0x00u && current[3] == 0x00u && current[4] == 0x00u &&
      current[5] == 0x90u && current[6] == 0x90u && current[7] == 0x90u && current[8] == 0x90u) {
    (void)patch_copy(SAMP_ADDR_WANTED_LEVEL_PATCH, g_runtime.wanted_level_patch_saved,
                     sizeof(g_runtime.wanted_level_patch_saved));
    runtime_tracef("wanted_level_patch: restore addr=0x%08lx size=%u evidence=STATIC_037",
                   (unsigned long)SAMP_ADDR_WANTED_LEVEL_PATCH, (unsigned)SAMP_WANTED_LEVEL_PATCH_SIZE);
  } else {
    runtime_tracef("wanted_level_patch: restore_skip target_changed=1 first=0x%02x evidence=TODO_VERIFY",
                   (unsigned)current[0]);
  }
  g_runtime.wanted_level_patch_owned = 0u;
}

static int patch_copy_expected_first_byte(uintptr_t addr, const void *src, size_t size, uint8_t expected_first,
                                          const char *label) {
  uint8_t before = 0u;
  int applied = 0;

  if (addr == 0u || src == NULL || size == 0u || label == NULL) {
    return 0;
  }

  before = read_game_u8(addr);
  if (before != expected_first && before != ((const uint8_t *)src)[0]) {
    runtime_tracef("pool_patch: skip label=%s addr=0x%08lx expected=0x%02x before=0x%02x "
                   "evidence=INFERRED,TODO_VERIFY",
                   label, (unsigned long)addr, (unsigned)expected_first, (unsigned)before);
    return 0;
  }

  applied = patch_copy(addr, src, size);
  runtime_tracef("pool_patch: %s label=%s addr=0x%08lx size=%lu before=0x%02x after=0x%02x "
                 "evidence=INFERRED,GTA_REVERSED_REF,TODO_VERIFY",
                 applied ? "apply" : "failed", label, (unsigned long)addr, (unsigned long)size,
                 (unsigned)before, (unsigned)read_game_u8(addr));
  return applied;
}

static int patch_push_imm32_expected_opcode(uintptr_t addr, uint32_t value, uint8_t expected_opcode,
                                            const char *label) {
  uint8_t patch[5] = {0x68u, 0x00u, 0x00u, 0x00u, 0x00u};
  uint32_t patched_value = 0u;
  int applied = 0;

  if (label == NULL) {
    return 0;
  }

  memcpy(&patch[1], &value, sizeof(value));
  applied = patch_copy_expected_first_byte(addr, patch, sizeof(patch), expected_opcode, label);
  if (memory_is_readable_compat((const void *)(uintptr_t)(addr + 1u), sizeof(patched_value))) {
    memcpy(&patched_value, (const void *)(uintptr_t)(addr + 1u), sizeof(patched_value));
  }
  runtime_tracef("pool_patch: push_imm32 label=%s requested=%lu patched=%lu applied=%d "
                 "opcode=0x%02x evidence=INFERRED,GTA_REVERSED_REF,TODO_VERIFY",
                 label, (unsigned long)value, (unsigned long)patched_value, applied,
                 (unsigned)read_game_u8(addr));
  return applied;
}

static int game_pointer_plausible_compat(uintptr_t ptr) {
  return ptr >= 0x10000u && ptr < 0xF0000000u;
}

static int patch_write_u32(uintptr_t addr, uint32_t value) {
  return patch_copy(addr, &value, sizeof(value));
}

static int patch_write_u8(uintptr_t addr, uint8_t value) {
  return patch_copy(addr, &value, sizeof(value));
}

static void center_hwnd_cursor_compat(HWND hwnd) {
  RECT rect;
  POINT center;

  if (hwnd == NULL || !GetClientRect(hwnd, &rect)) {
    return;
  }
  center.x = rect.left + ((rect.right - rect.left) / 2);
  center.y = rect.top + ((rect.bottom - rect.top) / 2);
  if (ClientToScreen(hwnd, &center)) {
    SetCursorPos(center.x, center.y);
  }
}

static void visible_cursor_recenter_patch_apply_compat(const char *reason) {
  const uint8_t ret_opcode = 0xC3u;
  uint8_t before = 0;
  int saved_now = 0;

  before = read_game_u8(SAMP_ADDR_RS_MOUSE_SET_POS);
  if (InterlockedCompareExchange(&g_runtime.rs_mouse_set_pos_saved_valid, 1, 0) == 0) {
    g_runtime.rs_mouse_set_pos_saved_byte = before;
    saved_now = 1;
  }
  if (before == ret_opcode) {
    InterlockedExchange(&g_runtime.rs_mouse_set_pos_cursor_patch_applied, 1);
    return;
  }
  if (patch_write_u8(SAMP_ADDR_RS_MOUSE_SET_POS, ret_opcode)) {
    InterlockedExchange(&g_runtime.rs_mouse_set_pos_cursor_patch_applied, 1);
    runtime_tracef("cursor_patch: apply reason=%s rs_mouse_set_pos=0x%02x->0x%02x saved=0x%02x saved_now=%d "
                   "evidence=INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before,
                   (unsigned)read_game_u8(SAMP_ADDR_RS_MOUSE_SET_POS),
                   (unsigned)g_runtime.rs_mouse_set_pos_saved_byte, saved_now);
  } else {
    runtime_tracef("cursor_patch: apply failed reason=%s rs_mouse_set_pos=0x%02x "
                   "evidence=INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before);
  }
}

static void visible_cursor_recenter_patch_restore_compat(const char *reason) {
  const uint8_t ret_opcode = 0xC3u;
  uint8_t before = 0;
  uint8_t restore_byte = 0x55u;

  if (InterlockedCompareExchange(&g_runtime.rs_mouse_set_pos_cursor_patch_applied, 0, 0) == 0) {
    return;
  }
  if (InterlockedCompareExchange(&g_runtime.rs_mouse_set_pos_saved_valid, 0, 0) != 0) {
    restore_byte = g_runtime.rs_mouse_set_pos_saved_byte;
  }

  before = read_game_u8(SAMP_ADDR_RS_MOUSE_SET_POS);
  if (before != ret_opcode) {
    InterlockedExchange(&g_runtime.rs_mouse_set_pos_cursor_patch_applied, 0);
    runtime_tracef("cursor_patch: restore skipped reason=%s current=0x%02x saved=0x%02x "
                   "evidence=INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before, (unsigned)restore_byte);
    return;
  }
  if (patch_write_u8(SAMP_ADDR_RS_MOUSE_SET_POS, restore_byte)) {
    InterlockedExchange(&g_runtime.rs_mouse_set_pos_cursor_patch_applied, 0);
    runtime_tracef("cursor_patch: restore reason=%s rs_mouse_set_pos=0x%02x->0x%02x "
                   "evidence=INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before,
                   (unsigned)read_game_u8(SAMP_ADDR_RS_MOUSE_SET_POS));
  } else {
    runtime_tracef("cursor_patch: restore failed reason=%s current=0x%02x saved=0x%02x "
                   "evidence=INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned)before, (unsigned)restore_byte);
  }
}

static void apply_resolution_unlock_patches_compat(void) {
  uint8_t jump_short = 0xEBu;
  int applied = 0;

  if (InterlockedCompareExchange(&g_runtime.resolution_unlock_patches_applied, 1, 0) != 0) {
    return;
  }

  applied += patch_nop(SAMP_ADDR_VIDEO_MODE_LIST_WIDTH_CHECK, 6u) ? 1 : 0;
  applied += patch_nop(SAMP_ADDR_VIDEO_MODE_LIST_HEIGHT_CHECK, 6u) ? 1 : 0;
  applied += patch_write_u8(SAMP_ADDR_VIDEO_MODE_LIST_ASPECT_CHECK, jump_short) ? 1 : 0;
  applied += patch_nop(SAMP_ADDR_VIDEO_MODE_LIST_VRAM_CHECK, 2u) ? 1 : 0;
  applied += patch_nop(SAMP_ADDR_DEVICE_DIALOG_WIDTH_CHECK, 6u) ? 1 : 0;
  applied += patch_nop(SAMP_ADDR_DEVICE_DIALOG_HEIGHT_CHECK, 6u) ? 1 : 0;
  applied += patch_write_u8(SAMP_ADDR_DEVICE_DIALOG_ASPECT_CHECK, jump_short) ? 1 : 0;

  runtime_tracef("resolution_unlock: applied=%d/7", applied);
}

static void apply_default_resolution_patch_compat(const samp_display_mode_request *request) {
  int width_ok = 0;
  int height_ok = 0;

  if (request == NULL) {
    return;
  }
  if (request->width < 640 || request->height < 480) {
    return;
  }
  if (InterlockedCompareExchange(&g_runtime.default_resolution_patch_applied, 1, 0) != 0) {
    return;
  }

  width_ok = patch_write_u32(SAMP_ADDR_DEFAULT_RES_WIDTH_IMM, (uint32_t)request->width);
  height_ok = patch_write_u32(SAMP_ADDR_DEFAULT_RES_HEIGHT_IMM, (uint32_t)request->height);
  runtime_tracef("resolution_unlock: default_res=%dx%d width_patch=%d height_patch=%d", request->width,
                 request->height, width_ok, height_ok);
}

static int env_flag_enabled_default_compat(const char *name, int default_enabled) {
  return runtime_flag_enabled_default_source_compat(name, default_enabled, NULL);
}

typedef struct samp_atomic_store_pointer_patch_compat {
  uintptr_t addr;
  uint32_t displacement;
} samp_atomic_store_pointer_patch_compat;

static uint32_t samp_asset_atomic_model_store_target_capacity_compat(void) {
  return object_compat_env_u32(SAMP_OBJECT_COMPAT_ATOMIC_STORE_CAPACITY_ENV, SAMP_GTA_ATOMIC_MODEL_INFO_COUNT,
                               SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT, SAMP_GTA_ATOMIC_MODEL_INFO_COUNT_MAX);
}

static size_t samp_asset_atomic_model_store_bytes_compat(uint32_t capacity) {
  return sizeof(uint32_t) + ((size_t)capacity * (size_t)SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);
}

static uintptr_t samp_asset_call_atomic_model_info_ctor_compat(uintptr_t model_info) {
#if defined(__i386__) || defined(_M_IX86)
  uintptr_t result = 0u;

  if (model_info < 0x10000u || !gta_code_ptr_compat((uintptr_t)SAMP_ADDR_MODEL_INFO_ATOMIC_CTOR)) {
    return 0u;
  }
  __asm__ __volatile__("movl %[model_info], %%ecx\n\t"
                       "call *%[ctor]\n\t"
                       "movl %%eax, %[result]\n\t"
                       : [result] "=r"(result)
                       : [model_info] "r"(model_info),
                         [ctor] "r"((uintptr_t)SAMP_ADDR_MODEL_INFO_ATOMIC_CTOR)
                       : "eax", "ecx", "edx", "memory", "cc");
  return result;
#else
  (void)model_info;
  return 0u;
#endif
}

static unsigned long samp_asset_construct_atomic_model_store_compat(uintptr_t store, uint32_t capacity) {
  const uintptr_t first_object = store + sizeof(uint32_t);
  uint32_t zero_count = 0u;
  uint32_t expected_vtable = 0u;
  unsigned long constructed = 0ul;
  uint32_t i = 0u;

  if (store < 0x10000u || capacity == 0u ||
      !memory_is_writable_compat((void *)store, samp_asset_atomic_model_store_bytes_compat(capacity)) ||
      !gta_code_ptr_compat((uintptr_t)SAMP_ADDR_MODEL_INFO_ATOMIC_CTOR)) {
    return 0ul;
  }

  memcpy((void *)store, &zero_count, sizeof(zero_count));
  for (i = 0u; i < capacity; ++i) {
    uintptr_t model_info = first_object + ((uintptr_t)i * (uintptr_t)SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);
    uintptr_t result = samp_asset_call_atomic_model_info_ctor_compat(model_info);
    uintptr_t vtable = 0u;

    if (result != model_info || !memory_is_readable_compat((const void *)model_info, sizeof(vtable))) {
      break;
    }
    memcpy(&vtable, (const void *)model_info, sizeof(vtable));
    if (vtable < 0x00800000u || vtable >= 0x00A00000u ||
        !memory_is_readable_compat((const void *)(vtable + 0x18u), sizeof(uintptr_t))) {
      break;
    }
    if (i == 0u) {
      expected_vtable = (uint32_t)vtable;
    } else if ((uint32_t)vtable != expected_vtable) {
      break;
    }
    ++constructed;
  }
  memcpy((void *)store, &zero_count, sizeof(zero_count));
  return constructed;
}

static int samp_asset_atomic_model_store_patch_pointer_compat(uintptr_t patch_addr, uint32_t old_value,
                                                              uint32_t new_value, const char *label) {
  uint32_t before = 0u;

  if (!read_game_u32_checked_compat(patch_addr, &before)) {
    runtime_tracef("atomic_store_expand: patch_skip label=%s addr=0x%08lx reason=unreadable "
                   "evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   label != NULL ? label : "unknown", (unsigned long)patch_addr);
    return 0;
  }
  if (before == new_value) {
    return 1;
  }
  if (before != old_value) {
    runtime_tracef("atomic_store_expand: patch_skip label=%s addr=0x%08lx reason=unexpected_pointer "
                   "expected=0x%08lx before=0x%08lx new=0x%08lx evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   label != NULL ? label : "unknown", (unsigned long)patch_addr, (unsigned long)old_value,
                   (unsigned long)before, (unsigned long)new_value);
    return 0;
  }
  if (!patch_write_u32(patch_addr, new_value)) {
    runtime_tracef("atomic_store_expand: patch_failed label=%s addr=0x%08lx old=0x%08lx new=0x%08lx "
                   "evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   label != NULL ? label : "unknown", (unsigned long)patch_addr, (unsigned long)old_value,
                   (unsigned long)new_value);
    return 0;
  }
  return 1;
}

static unsigned long samp_asset_atomic_model_store_fix_model_ptrs_compat(uintptr_t old_store, uintptr_t new_store,
                                                                         LONG count) {
  uintptr_t old_begin = old_store + sizeof(uint32_t);
  uintptr_t new_begin = new_store + sizeof(uint32_t);
  uintptr_t old_end = 0u;
  LONG scan_count = count;
  LONG i = 0;
  unsigned long fixed = 0ul;

  if (scan_count < 0 || scan_count > (LONG)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT) {
    scan_count = (LONG)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT;
  }
  old_end = old_begin + ((uintptr_t)scan_count * (uintptr_t)SAMP_MODEL_INFO_ATOMIC_SYNTHETIC_BYTES);

  for (i = 0; i < (LONG)SAMP_GTA_MODEL_INFO_COUNT; ++i) {
    uintptr_t slot_addr = (uintptr_t)SAMP_ADDR_MODEL_INFO_PTRS + ((uintptr_t)i * sizeof(uintptr_t));
    uintptr_t ptr = 0u;
    uintptr_t relocated = 0u;

    if (!memory_is_readable_compat((const void *)slot_addr, sizeof(ptr)) ||
        !memory_is_writable_compat((void *)slot_addr, sizeof(ptr))) {
      continue;
    }
    memcpy(&ptr, (const void *)slot_addr, sizeof(ptr));
    if (ptr < old_begin || ptr >= old_end) {
      continue;
    }
    relocated = new_begin + (ptr - old_begin);
    memcpy((void *)slot_addr, &relocated, sizeof(relocated));
    ++fixed;
  }
  return fixed;
}

static int samp_asset_expand_atomic_model_store_compat(const char *reason) {
  static const samp_atomic_store_pointer_patch_compat kAtomicStorePointers[] = {
      {0x4C63E1u, 0x00u}, {0x4C63FEu, 0x00u}, {0x4C65DAu, 0x00u}, {0x4C6621u, 0x00u},
      {0x4C6633u, 0x00u}, {0x4C6865u, 0x00u}, {0x4C689Au, 0x00u}, {0x4C68B5u, 0x00u},
      {0x4C68E8u, 0x00u}, {0x4C68F9u, 0x00u}, {0x4C6927u, 0x00u}, {0x4C6938u, 0x00u},
      {0x4C6966u, 0x00u}, {0x4C6977u, 0x00u}, {0x4C69A5u, 0x00u}, {0x4C69B6u, 0x00u},
      {0x4C69E4u, 0x00u}, {0x4C69F5u, 0x00u}, {0x4C6A23u, 0x00u}, {0x4C6A34u, 0x00u},
      {0x4C63F2u, 0x04u}, {0x4C662Du, 0x04u}, {0x4C6822u, 0x04u}, {0x4C6829u, 0x04u},
      {0x4C6877u, 0x04u}, {0x4C6881u, 0x04u}, {0x4C6890u, 0x04u}, {0x4C68A5u, 0x04u},
      {0x4C68F3u, 0x04u}, {0x4C6932u, 0x04u}, {0x4C6971u, 0x04u}, {0x4C69B0u, 0x04u},
      {0x4C69EFu, 0x04u}, {0x4C6A2Eu, 0x04u}, {0x4C68ACu, 0x1Cu},
  };
  const uintptr_t old_store = SAMP_ADDR_MODEL_INFO_ATOMIC_STORE_COUNT;
  uint32_t capacity = samp_asset_atomic_model_store_target_capacity_compat();
  uintptr_t new_store = g_runtime.samp_asset_atomic_store_dynamic;
  LONG count_before = -1;
  LONG count_after = -1;
  size_t bytes = 0u;
  size_t i = 0u;
  unsigned long patched = 0ul;
  unsigned long constructed = 0ul;
  unsigned long fixed_model_ptrs = 0ul;

  if (!env_flag_enabled_default_compat(SAMP_OBJECT_COMPAT_ATOMIC_STORE_EXPAND_ENV, 1)) {
    runtime_tracef("atomic_store_expand: disabled reason=%s env=%s evidence=OBSERVED_037,PROBE_TRACE,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", SAMP_OBJECT_COMPAT_ATOMIC_STORE_EXPAND_ENV);
    return 0;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_atomic_store_expanded, 0, 0) != 0) {
    return 1;
  }
  if (InterlockedCompareExchange(&g_runtime.samp_asset_atomic_store_expand_attempted, 1, 0) != 0) {
    return samp_asset_atomic_model_store_expanded_compat();
  }
  if (capacity <= SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT) {
    runtime_tracef("atomic_store_expand: skipped reason=%s capacity=%lu vanilla=%u env=%s "
                   "evidence=OBSERVED_037,PROBE_TRACE,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned long)capacity,
                   (unsigned)SAMP_GTA_VANILLA_ATOMIC_MODEL_INFO_COUNT,
                   SAMP_OBJECT_COMPAT_ATOMIC_STORE_CAPACITY_ENV);
    return 0;
  }
  if (!samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &count_before)) {
    runtime_tracef("atomic_store_expand: skipped reason=%s cause=count_unreadable addr=0x%08lx "
                   "evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", (unsigned long)SAMP_ADDR_MODEL_INFO_ATOMIC_STORE_COUNT);
    return 0;
  }

  bytes = samp_asset_atomic_model_store_bytes_compat(capacity);
  if (new_store == 0u) {
    new_store = (uintptr_t)HeapAlloc(GetProcessHeap(), HEAP_ZERO_MEMORY, bytes);
    if (new_store == 0u) {
      runtime_tracef("atomic_store_expand: failed reason=%s cause=alloc bytes=%lu capacity=%lu "
                     "evidence=OBSERVED_037,PROBE_TRACE,INFERRED,TODO_VERIFY",
                     reason != NULL ? reason : "unknown", (unsigned long)bytes, (unsigned long)capacity);
      return 0;
    }
    g_runtime.samp_asset_atomic_store_dynamic = new_store;
  }

  constructed = samp_asset_construct_atomic_model_store_compat(new_store, capacity);
  if (constructed != (unsigned long)capacity) {
    if (g_runtime.samp_asset_atomic_store_dynamic == new_store) {
      g_runtime.samp_asset_atomic_store_dynamic = 0u;
    }
    HeapFree(GetProcessHeap(), 0, (void *)new_store);
    runtime_tracef("atomic_store_expand: failed reason=%s cause=construct constructed=%lu/%lu "
                   "ctor=0x%08lx store=0x%08lx evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", constructed, (unsigned long)capacity,
                   (unsigned long)SAMP_ADDR_MODEL_INFO_ATOMIC_CTOR, (unsigned long)new_store);
    return 0;
  }

  for (i = 0u; i < sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0]); ++i) {
    const samp_atomic_store_pointer_patch_compat *patch = &kAtomicStorePointers[i];
    uint32_t before = 0u;
    uint32_t old_value = (uint32_t)(old_store + (uintptr_t)patch->displacement);
    uint32_t new_value = (uint32_t)(new_store + (uintptr_t)patch->displacement);

    if (!read_game_u32_checked_compat(patch->addr, &before) || (before != old_value && before != new_value)) {
      runtime_tracef("atomic_store_expand: validate_failed reason=%s addr=0x%08lx displacement=0x%02lx "
                     "expected=0x%08lx current=0x%08lx new=0x%08lx patched=0 "
                     "evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                     reason != NULL ? reason : "unknown", (unsigned long)patch->addr,
                     (unsigned long)patch->displacement, (unsigned long)old_value, (unsigned long)before,
                     (unsigned long)new_value);
      return 0;
    }
  }

  for (i = 0u; i < sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0]); ++i) {
    const samp_atomic_store_pointer_patch_compat *patch = &kAtomicStorePointers[i];
    uint32_t old_value = (uint32_t)(old_store + (uintptr_t)patch->displacement);
    uint32_t new_value = (uint32_t)(new_store + (uintptr_t)patch->displacement);

    if (samp_asset_atomic_model_store_patch_pointer_compat(patch->addr, old_value, new_value, "atomic_models")) {
      ++patched;
    }
  }

  if (patched != (unsigned long)(sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0]))) {
    for (i = 0u; i < sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0]); ++i) {
      const samp_atomic_store_pointer_patch_compat *patch = &kAtomicStorePointers[i];
      uint32_t current = 0u;
      uint32_t old_value = (uint32_t)(old_store + (uintptr_t)patch->displacement);
      uint32_t new_value = (uint32_t)(new_store + (uintptr_t)patch->displacement);

      if (read_game_u32_checked_compat(patch->addr, &current) && current == new_value) {
        (void)patch_write_u32(patch->addr, old_value);
      }
    }
    runtime_tracef("atomic_store_expand: incomplete reason=%s patched=%lu/%lu store=0x%08lx capacity=%lu "
                   "rollback=1 evidence=GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                   reason != NULL ? reason : "unknown", patched,
                   (unsigned long)(sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0])),
                   (unsigned long)new_store, (unsigned long)capacity);
    return 0;
  }

  g_runtime.samp_asset_atomic_store_capacity = capacity;
  InterlockedExchange(&g_runtime.samp_asset_atomic_store_expanded, 1);
  fixed_model_ptrs = samp_asset_atomic_model_store_fix_model_ptrs_compat(old_store, new_store, count_before);
  (void)samp_asset_read_model_info_store_count_compat(SAMP_ADDR_MODEL_INFO_ADD_ATOMIC, &count_after);

  runtime_tracef("atomic_store_expand: applied reason=%s old=0x%08lx new=0x%08lx capacity=%lu bytes=%lu "
                 "count=%ld->%ld constructed=%lu patched=%lu/%lu fixed_model_ptrs=%lu env=%s "
                 "evidence=OBSERVED_037,PROBE_TRACE,"
                 "GTA_REVERSED_REF,INFERRED,TODO_VERIFY",
                 reason != NULL ? reason : "unknown", (unsigned long)old_store, (unsigned long)new_store,
                 (unsigned long)capacity, (unsigned long)bytes, (long)count_before, (long)count_after, constructed,
                 patched, (unsigned long)(sizeof(kAtomicStorePointers) / sizeof(kAtomicStorePointers[0])), fixed_model_ptrs,
                 SAMP_OBJECT_COMPAT_ATOMIC_STORE_EXPAND_ENV);
  return 1;
}

static void display_mode_desktop_request_compat(samp_display_mode_request *request) {
  HDC dc = NULL;
  int depth = 32;
  int width = 800;
  int height = 600;

  if (request == NULL) {
    return;
  }

  width = GetSystemMetrics(SM_CXSCREEN);
  height = GetSystemMetrics(SM_CYSCREEN);
  dc = GetDC(NULL);
  if (dc != NULL) {
    int caps_depth = GetDeviceCaps(dc, BITSPIXEL);
    if (caps_depth >= 16) {
      depth = caps_depth;
    }
    ReleaseDC(NULL, dc);
  }
  if (width < 640) {
    width = 800;
  }
  if (height < 480) {
    height = 600;
  }

  request->width = width;
  request->height = height;
  request->depth = depth;
  request->adapter = 0;
}

static int parse_display_mode_request_compat(const char *text, samp_display_mode_request *request) {
  const char *cursor = text;
  char *endptr = NULL;
  unsigned long values[4] = {0, 0, 0, 0};
  int count = 0;

  if (text == NULL || *text == '\0' || request == NULL) {
    return 0;
  }

  while (*cursor != '\0' && count < 4) {
    values[count] = strtoul(cursor, &endptr, 10);
    if (endptr == cursor || values[count] > 8192UL) {
      return 0;
    }
    ++count;
    cursor = endptr;
    if (*cursor == 'x' || *cursor == 'X') {
      ++cursor;
      continue;
    }
    break;
  }

  if (*cursor != '\0' || count < 2 || values[0] < 640UL || values[1] < 480UL) {
    return 0;
  }

  request->width = (int)values[0];
  request->height = (int)values[1];
  request->depth = (count >= 3 && values[2] >= 16UL) ? (int)values[2] : request->depth;
  request->adapter = (count >= 4) ? (int)values[3] : request->adapter;
  return 1;
}

static void load_display_mode_request_compat(samp_display_mode_request *request) {
  const char *env_value = NULL;
  samp_display_mode_request parsed;

  if (request == NULL) {
    return;
  }

  display_mode_desktop_request_compat(request);
  parsed = *request;
  env_value = getenv("SAMPDLL_DISPLAY_RESOLUTION");
  if (env_value != NULL && *env_value != '\0') {
    if (parse_display_mode_request_compat(env_value, &parsed)) {
      *request = parsed;
    } else {
      runtime_tracef("select_device: ignored invalid SAMPDLL_DISPLAY_RESOLUTION='%s'", env_value);
    }
  }
}

static uint32_t video_mode_score_compat(const samp_rw_video_mode *mode, const samp_display_mode_request *request) {
  uint32_t score = 0;
  uint32_t width_delta = 0;
  uint32_t height_delta = 0;

  if (mode == NULL || request == NULL) {
    return 0xFFFFFFFFu;
  }

  width_delta = (mode->width > request->width) ? (uint32_t)(mode->width - request->width)
                                               : (uint32_t)(request->width - mode->width);
  height_delta = (mode->height > request->height) ? (uint32_t)(mode->height - request->height)
                                                  : (uint32_t)(request->height - mode->height);
  score = width_delta + height_delta;
  if (mode->depth != request->depth) {
    score += 100000u;
  }
  if (mode->width > request->width || mode->height > request->height) {
    score += 1000u;
  }
  return score;
}

static int d3d9_display_mode_depth_compat(uint32_t format) {
  if (format == SAMP_D3DFMT_X8R8G8B8) {
    return 32;
  }
  if (format == SAMP_D3DFMT_R5G6B5) {
    return 16;
  }
  return 0;
}

static uint32_t d3d9_display_mode_format_for_depth_compat(int depth) {
  return (depth >= 32) ? SAMP_D3DFMT_X8R8G8B8 : SAMP_D3DFMT_R5G6B5;
}

static int display_mode_index_is_used_compat(int index, const int *used_indices, int used_count) {
  int i = 0;

  if (used_indices == NULL || used_count <= 0) {
    return 0;
  }
  for (i = 0; i < used_count; ++i) {
    if (used_indices[i] == index) {
      return 1;
    }
  }
  return 0;
}

static int force_display_mode_slot_compat(const samp_display_mode_request *request, const int *used_indices,
                                          int used_count) {
  samp_d3d9_display_mode_compat *modes = NULL;
  samp_d3d9_display_mode_compat forced;
  int count = 0;
  int exact_index = -1;
  int best_index = -1;
  uint32_t best_score = 0xFFFFFFFFu;
  int i = 0;

  if (request == NULL) {
    return -1;
  }

  count = *(volatile int32_t *)(uintptr_t)SAMP_ADDR_D3D9_NUM_DISPLAY_MODES;
  modes = *(samp_d3d9_display_mode_compat **)(uintptr_t)SAMP_ADDR_D3D9_DISPLAY_MODES;
  if (count <= 0 || count > 4096 || !game_pointer_plausible_compat((uintptr_t)modes)) {
    runtime_tracef("display_mode_force: skipped count=%d modes=%p target=%dx%dx%d", count, modes, request->width,
                   request->height, request->depth);
    return -1;
  }

  for (i = 0; i < count; ++i) {
    samp_rw_video_mode score_mode;
    int depth = d3d9_display_mode_depth_compat(modes[i].format);
    uint32_t score = 0;

    if ((modes[i].flags & SAMP_RW_VIDEOMODE_EXCLUSIVE) == 0) {
      continue;
    }
    if (modes[i].width < 640u || modes[i].height < 480u) {
      continue;
    }
    if ((int)modes[i].width == request->width && (int)modes[i].height == request->height &&
        (request->depth <= 0 || depth == request->depth)) {
      exact_index = i;
      break;
    }
    if (display_mode_index_is_used_compat(i, used_indices, used_count)) {
      continue;
    }

    memset(&score_mode, 0, sizeof(score_mode));
    score_mode.width = (int32_t)modes[i].width;
    score_mode.height = (int32_t)modes[i].height;
    score_mode.depth = depth > 0 ? depth : 32;
    score_mode.flags = modes[i].flags;
    score = video_mode_score_compat(&score_mode, request);
    if (best_index < 0 || score < best_score) {
      best_index = i;
      best_score = score;
    }
  }

  if (exact_index >= 0) {
    runtime_tracef("display_mode_force: target=%dx%dx%d already present index=%d", request->width, request->height,
                   request->depth, exact_index);
    return exact_index;
  }
  if (best_index < 0) {
    runtime_tracef("display_mode_force: no replacement slot for target=%dx%dx%d count=%d", request->width,
                   request->height, request->depth, count);
    return -1;
  }

  forced.width = (uint32_t)request->width;
  forced.height = (uint32_t)request->height;
  forced.refresh_rate = 0u;
  forced.format = d3d9_display_mode_format_for_depth_compat(request->depth);
  forced.flags = SAMP_RW_VIDEOMODE_EXCLUSIVE;
  if (!patch_copy((uintptr_t)&modes[best_index], &forced, sizeof(forced))) {
    runtime_tracef("display_mode_force: patch failed index=%d target=%dx%dx%d", best_index, request->width,
                   request->height, request->depth);
    return -1;
  }

  runtime_tracef("display_mode_force: replaced index=%d target=%dx%dx%d format=%lu old_score=%lu count=%d", best_index,
                 request->width, request->height, request->depth, (unsigned long)forced.format,
                 (unsigned long)best_score, count);
  return best_index;
}

static void force_startup_display_modes_compat(const samp_display_mode_request *request) {
  samp_display_mode_request extra;
  const char *extra_env = NULL;
  int used_indices[4] = {-1, -1, -1, -1};
  int used_count = 0;
  int forced = -1;

  memset(&extra, 0, sizeof(extra));
  extra.width = 2560;
  extra.height = 1440;
  extra.depth = 32;
  extra.adapter = 0;

  extra_env = getenv("SAMPDLL_EXTRA_RESOLUTION");
  if (extra_env != NULL && *extra_env != '\0') {
    samp_display_mode_request parsed = extra;
    if (parse_display_mode_request_compat(extra_env, &parsed)) {
      extra = parsed;
    } else {
      runtime_tracef("display_mode_force: ignored invalid SAMPDLL_EXTRA_RESOLUTION='%s'", extra_env);
    }
  }

  forced = force_display_mode_slot_compat(&extra, used_indices, used_count);
  if (forced >= 0 && used_count < (int)(sizeof(used_indices) / sizeof(used_indices[0]))) {
    used_indices[used_count++] = forced;
  }
  if (request != NULL && (request->width != extra.width || request->height != extra.height || request->depth != extra.depth)) {
    forced = force_display_mode_slot_compat(request, used_indices, used_count);
    if (forced >= 0 && used_count < (int)(sizeof(used_indices) / sizeof(used_indices[0]))) {
      used_indices[used_count++] = forced;
    }
  }
}

static int find_best_video_mode_compat(const samp_display_mode_request *request, samp_rw_video_mode *best_mode) {
  samp_rw_get_num_video_modes_fn get_num_video_modes = (samp_rw_get_num_video_modes_fn)(uintptr_t)SAMP_ADDR_RW_ENGINE_GET_NUM_VIDEO_MODES;
  samp_rw_get_video_mode_info_fn get_video_mode_info =
      (samp_rw_get_video_mode_info_fn)(uintptr_t)SAMP_ADDR_RW_ENGINE_GET_VIDEO_MODE_INFO;
  int num_modes = 0;
  int best_index = -1;
  uint32_t best_score = 0xFFFFFFFFu;
  int i = 0;

  if (request == NULL || best_mode == NULL) {
    return -1;
  }

  memset(best_mode, 0, sizeof(*best_mode));
  num_modes = get_num_video_modes();
  if (num_modes <= 0 || num_modes > 4096) {
    runtime_tracef("select_device: invalid video mode count=%d", num_modes);
    return -1;
  }

  for (i = 0; i < num_modes; ++i) {
    samp_rw_video_mode mode;
    uint32_t score = 0;

    memset(&mode, 0, sizeof(mode));
    if (get_video_mode_info(&mode, (unsigned int)i) == NULL) {
      continue;
    }
    if (mode.width < 640 || mode.height < 480) {
      continue;
    }
    if ((mode.flags & SAMP_RW_VIDEOMODE_EXCLUSIVE) == 0) {
      continue;
    }

    score = video_mode_score_compat(&mode, request);
    if (best_index < 0 || score < best_score) {
      best_index = i;
      best_score = score;
      *best_mode = mode;
    }
  }

  runtime_tracef("select_device: modes=%d requested=%dx%dx%d adapter=%d best=%d best_mode=%dx%dx%d flags=0x%x score=%lu",
                 num_modes, request->width, request->height, request->depth, request->adapter, best_index,
                 best_mode->width, best_mode->height, best_mode->depth, (unsigned int)best_mode->flags,
                 (unsigned long)best_score);
  return best_index;
}

static int apply_startup_video_mode_compat(int *out_num_subsystems) {
  samp_rw_get_num_subsystems_fn get_num_subsystems =
      (samp_rw_get_num_subsystems_fn)(uintptr_t)SAMP_ADDR_RW_ENGINE_GET_NUM_SUBSYSTEMS;
  samp_rw_set_subsystem_fn set_subsystem = (samp_rw_set_subsystem_fn)(uintptr_t)SAMP_ADDR_RW_ENGINE_SET_SUBSYSTEM;
  samp_display_mode_request request;
  samp_rw_video_mode best_mode;
  int num_subsystems = 0;
  int best_index = -1;

  if (out_num_subsystems != NULL) {
    *out_num_subsystems = 0;
  }
  num_subsystems = get_num_subsystems();
  if (out_num_subsystems != NULL) {
    *out_num_subsystems = num_subsystems;
  }
  if (InterlockedCompareExchange(&g_runtime.select_device_video_mode_applied, 1, 0) != 0) {
    return 1;
  }

  load_display_mode_request_compat(&request);
  apply_default_resolution_patch_compat(&request);
  if (num_subsystems > 0 && request.adapter >= 0 && request.adapter < num_subsystems) {
    int subsystem_result = set_subsystem(request.adapter);
    (void)patch_write_u32(SAMP_ADDR_FRONTEND_CUR_ADAPTER, (uint32_t)request.adapter);
    runtime_tracef("select_device: adapters=%d selected_adapter=%d set_result=%d", num_subsystems, request.adapter,
                   subsystem_result);
  } else {
    runtime_tracef("select_device: adapters=%d requested_adapter=%d not selected", num_subsystems, request.adapter);
  }

  force_startup_display_modes_compat(&request);
  best_index = find_best_video_mode_compat(&request, &best_mode);
  if (best_index < 0) {
    return 0;
  }

  (void)patch_write_u32(SAMP_ADDR_FRONTEND_CUR_VIDEO_MODE, (uint32_t)best_index);
  (void)patch_write_u32(SAMP_ADDR_FRONTEND_SAVED_VIDEO_MODE, (uint32_t)best_index);
  runtime_tracef("select_device: applied mode_index=%d mode=%dx%dx%d ref=%d format=%d", best_index, best_mode.width,
                 best_mode.height, best_mode.depth, best_mode.ref_rate, best_mode.format);
  return 1;
}

static int __cdecl select_device_on_call_compat(void) {
  int num_subsystems = 0;
  int applied = 0;
  int dialog_enabled = 0;
  int force_dialog = 0;
  int result = 0;

  applied = apply_startup_video_mode_compat(&num_subsystems);
  dialog_enabled = env_flag_enabled_default_compat("SAMPDLL_DEVICE_SELECTION", 1);
  force_dialog = env_flag_enabled_default_compat("SAMPDLL_DEVICE_SELECTION_FORCE", 0);

  if (dialog_enabled && (num_subsystems > 1 || force_dialog)) {
    result = 1;
  } else if (num_subsystems > 1) {
    result = 2;
  } else {
    result = 0;
  }

  runtime_tracef("select_device: applied=%d adapters=%d dialog=%d force=%d result=%d", applied, num_subsystems,
                 dialog_enabled, force_dialog, result);
  return result;
}

static void write_u32_unaligned_compat(uint8_t *dst, uint32_t value) {
  if (dst == NULL) {
    return;
  }
  dst[0] = (uint8_t)(value & 0xFFu);
  dst[1] = (uint8_t)((value >> 8u) & 0xFFu);
  dst[2] = (uint8_t)((value >> 16u) & 0xFFu);
  dst[3] = (uint8_t)((value >> 24u) & 0xFFu);
}

static int build_select_device_stub_compat(uint8_t *code, size_t code_size) {
  size_t n = 0;
  size_t single_branch = 0;
  size_t show_branch = 0;
  size_t single_label = 0;
  size_t show_label = 0;

  if (code == NULL || code_size < SAMP_SELECT_DEVICE_STUB_SIZE || sizeof(uintptr_t) != 4u) {
    return 0;
  }

  memset(code, 0xCC, code_size);
  code[n++] = 0x60u; /* pushad */
  code[n++] = 0xB8u; /* mov eax, select_device_on_call_compat */
  write_u32_unaligned_compat(&code[n], (uint32_t)(uintptr_t)select_device_on_call_compat);
  n += 4u;
  code[n++] = 0xFFu; /* call eax */
  code[n++] = 0xD0u;
  code[n++] = 0x83u; /* cmp eax, 1 */
  code[n++] = 0xF8u;
  code[n++] = 0x01u;
  code[n++] = 0x61u; /* popad, flags from cmp are preserved */

  single_branch = n;
  code[n++] = 0x7Cu; /* jl single */
  code[n++] = 0x00u;
  show_branch = n;
  code[n++] = 0x74u; /* je multi show */
  code[n++] = 0x00u;

  code[n++] = 0xB8u; /* mov eax, 1; MTA-compatible multi-hide path */
  write_u32_unaligned_compat(&code[n], 1u);
  n += 4u;
  code[n++] = 0x68u; /* push RETURN_MULTI_HIDE */
  write_u32_unaligned_compat(&code[n], SAMP_ADDR_SELECT_DEVICE_RETURN_MULTI_HIDE);
  n += 4u;
  code[n++] = 0xC3u; /* ret */

  single_label = n;
  code[single_branch + 1u] = (uint8_t)(single_label - (single_branch + 2u));
  code[n++] = 0x68u; /* push RETURN_SINGLE */
  write_u32_unaligned_compat(&code[n], SAMP_ADDR_SELECT_DEVICE_RETURN_SINGLE);
  n += 4u;
  code[n++] = 0xC3u;

  show_label = n;
  code[show_branch + 1u] = (uint8_t)(show_label - (show_branch + 2u));
  code[n++] = 0x68u; /* push RETURN_MULTI_SHOW */
  write_u32_unaligned_compat(&code[n], SAMP_ADDR_SELECT_DEVICE_RETURN_MULTI_SHOW);
  n += 4u;
  code[n++] = 0xC3u;

  return (n <= code_size) ? 1 : 0;
}

static void install_select_device_hook_compat(void) {
  uint8_t *stub = NULL;
  uint8_t patch[SAMP_SELECT_DEVICE_HOOK_SIZE] = {0};

  if (!env_flag_enabled_default_compat("SAMPDLL_SELECT_DEVICE_HOOK", 1)) {
    runtime_tracef("select_device_hook: disabled by env");
    return;
  }
  if (InterlockedCompareExchange(&g_runtime.select_device_hook_attempted, 1, 0) != 0) {
    return;
  }
  if (sizeof(uintptr_t) != 4u) {
    runtime_tracef("select_device_hook: skipped because pointer size is %lu", (unsigned long)sizeof(uintptr_t));
    return;
  }

  stub = (uint8_t *)VirtualAlloc(NULL, SAMP_SELECT_DEVICE_STUB_SIZE, MEM_COMMIT | MEM_RESERVE, PAGE_EXECUTE_READWRITE);
  if (stub == NULL) {
    runtime_tracef("select_device_hook: stub allocation failed gle=%lu", (unsigned long)GetLastError());
    return;
  }
  if (!build_select_device_stub_compat(stub, SAMP_SELECT_DEVICE_STUB_SIZE)) {
    VirtualFree(stub, 0u, MEM_RELEASE);
    runtime_tracef("select_device_hook: stub build failed");
    return;
  }
  FlushInstructionCache(GetCurrentProcess(), stub, SAMP_SELECT_DEVICE_STUB_SIZE);

  memcpy(g_runtime.select_device_hook_saved_code, (const void *)(uintptr_t)SAMP_ADDR_SELECT_DEVICE_HOOK,
         sizeof(g_runtime.select_device_hook_saved_code));
  g_runtime.select_device_hook_stub = (uintptr_t)stub;

  patch[0] = 0xFFu; /* jmp dword ptr [&g_runtime.select_device_hook_stub] */
  patch[1] = 0x25u;
  write_u32_unaligned_compat(&patch[2], (uint32_t)(uintptr_t)&g_runtime.select_device_hook_stub);
  if (!patch_copy(SAMP_ADDR_SELECT_DEVICE_HOOK, patch, sizeof(patch))) {
    g_runtime.select_device_hook_stub = 0u;
    VirtualFree(stub, 0u, MEM_RELEASE);
    runtime_tracef("select_device_hook: patch failed");
    return;
  }

  InterlockedExchange(&g_runtime.select_device_hook_installed, 1);
  runtime_tracef("select_device_hook: installed hook=0x%lx stub=%p saved=%02x %02x %02x %02x %02x %02x",
                 (unsigned long)SAMP_ADDR_SELECT_DEVICE_HOOK, stub, g_runtime.select_device_hook_saved_code[0],
                 g_runtime.select_device_hook_saved_code[1], g_runtime.select_device_hook_saved_code[2],
                 g_runtime.select_device_hook_saved_code[3], g_runtime.select_device_hook_saved_code[4],
                 g_runtime.select_device_hook_saved_code[5]);
}

static void uninstall_select_device_hook_compat(void) {
  uintptr_t stub = 0u;

  if (!InterlockedCompareExchange(&g_runtime.select_device_hook_installed, 0, 0)) {
    return;
  }

  (void)patch_copy(SAMP_ADDR_SELECT_DEVICE_HOOK, g_runtime.select_device_hook_saved_code,
                   sizeof(g_runtime.select_device_hook_saved_code));
  InterlockedExchange(&g_runtime.select_device_hook_installed, 0);
  stub = g_runtime.select_device_hook_stub;
  g_runtime.select_device_hook_stub = 0u;
  if (stub != 0u) {
    VirtualFree((void *)stub, 0u, MEM_RELEASE);
  }
  runtime_tracef("select_device_hook: uninstalled");
}

static int patch_zero_memory(uintptr_t addr, size_t size) {
  DWORD old_protect = 0;
  DWORD old_protect_restore = 0;

  if (addr == 0u || size == 0u) {
    return 0;
  }
  if (!VirtualProtect((LPVOID)addr, size, PAGE_EXECUTE_READWRITE, &old_protect)) {
    return 0;
  }
  memset((void *)addr, 0, size);
  FlushInstructionCache(GetCurrentProcess(), (LPCVOID)addr, size);
  (void)VirtualProtect((LPVOID)addr, size, old_protect, &old_protect_restore);
  return 1;
}

